const CROSS_REFERENCES = {"1:1": [{"ref": "2 Ne 16:1", "source": "bom", "text": "In the year that king Uzziah died, I saw also the Lord sitting upon a throne, high and lifted up, and his train filled the temple."}, {"ref": "Micah 1:1", "source": "ot", "text": "The word of the LORD that came to Micah the Morasthite in the days of Jotham, Ahaz, and Hezekiah, kings of Judah, which he saw concerning Samaria and Jerusalem."}], "1:2": [{"ref": "Deut 32:1", "source": "ot", "text": "Give ear, O ye heavens, and I will speak; and hear, O earth, the words of my mouth."}, {"ref": "Mosiah 16:1", "source": "bom", "text": "And now, it came to pass that after Abinadi had spoken these words he stretched forth his hand and said: The time shall come when all shall see the salvation of the Lord; when every nation, kindred, tongue, and people shall see eye to eye and shall confess before God that his judgments are just."}], "1:4": [{"ref": "Jer 2:13", "source": "ot", "text": "For my people have committed two evils; they have forsaken me the fountain of living waters, and hewed them out cisterns, broken cisterns, that can hold no water."}], "1:9": [{"ref": "Gen 19:24", "source": "ot", "text": "Then the LORD rained upon Sodom and upon Gomorrah brimstone and fire from the LORD out of heaven;"}, {"ref": "Rom 9:29", "source": "nt", "text": "And as Esaias said before, Except the Lord of Sabaoth had left us a seed, we had been as Sodoma, and been made like unto Gomorrha."}], "1:10": [{"ref": "Deut 32:32", "source": "ot", "text": "For their vine is of the vine of Sodom, and of the fields of Gomorrah: their grapes are grapes of gall, their clusters are bitter:"}, {"ref": "Ezek 16:46", "source": "ot", "text": "And thine elder sister is Samaria, she and her daughters that dwell at thy left hand: and thy younger sister, that dwelleth at thy right hand, is Sodom and her daughters."}], "1:11": [{"ref": "Amos 5:21-22", "source": "ot", "text": "I hate, I despise your feast days, and I will not smell in your solemn assemblies."}, {"ref": "Micah 6:7", "source": "ot", "text": "Will the LORD be pleased with thousands of rams, or with ten thousands of rivers of oil? shall I give my firstborn for my transgression, the fruit of my body for the sin of my soul?"}], "1:16": [{"ref": "James 4:8", "source": "nt", "text": "Draw nigh to God, and he will draw nigh to you. Cleanse your hands, ye sinners; and purify your hearts, ye double minded."}], "1:18": [{"ref": "Ps 51:7", "source": "ot", "text": "Purge me with hyssop, and I shall be clean: wash me, and I shall be whiter than snow."}, {"ref": "D&C 1:32", "source": "dc", "text": "Nevertheless, he that repents and does the commandments of the Lord shall be forgiven;"}], "1:19": [{"ref": "Deut 28:1-2", "source": "ot", "text": "And it shall come to pass, if thou shalt hearken diligently unto the voice of the LORD thy God, to observe and to do all his commandments which I command thee this day, that the LORD thy God will set thee on high above all nations of the earth:"}], "1:20": [{"ref": "Lev 26:25", "source": "ot", "text": "And I will bring a sword upon you, that shall avenge the quarrel of my covenant: and when ye are gathered together within your cities, I will send the pestilence among you; and ye shall be delivered into the hand of the enemy."}], "1:24": [{"ref": "2 Ne 15:24", "source": "bom", "text": "Therefore, as the fire devoureth the stubble, and the flame consumeth the chaff, their root shall be rottenness, and their blossoms shall go up as dust; because they have cast away the law of the Lord of Hosts, and despised the word of the Holy One of Israel."}], "1:25": [{"ref": "Mal 3:3", "source": "ot", "text": "And he shall sit as a refiner and purifier of silver: and he shall purify the sons of Levi, and purge them as gold and silver, that they may offer unto the LORD an offering in righteousness."}, {"ref": "Zech 13:9", "source": "ot", "text": "And I will bring the third part through the fire, and will refine them as silver is refined, and will try them as gold is tried: they shall call on my name, and I will hear them: I will say, It is my people: and they shall say, The LORD is my God."}], "1:26": [{"ref": "Jer 33:7", "source": "ot", "text": "And I will cause the captivity of Judah and the captivity of Israel to return, and will build them, as at the first."}], "1:27": [{"ref": "2 Ne 1:27", "source": "bom", "text": "And it must needs be that the power of God must be with him, even unto his commanding you that ye must obey. But behold, it was not he, but it was the Spirit of the Lord which was in him, which opened his mouth to utterance that he could not shut it."}], "2:1": [{"ref": "2 Ne 12:1", "source": "bom", "text": "The word that Isaiah, the son of Amoz, saw concerning Judah and Jerusalem:"}], "2:2": [{"ref": "Micah 4:1-2", "source": "ot", "text": "But in the last days it shall come to pass, that the mountain of the house of the LORD shall be established in the top of the mountains, and it shall be exalted above the hills; and people shall flow unto it."}, {"ref": "2 Ne 12:2", "source": "bom", "text": "And it shall come to pass in the last days, when the mountain of the Lord's house shall be established in the top of the mountains, and shall be exalted above the hills, and all nations shall flow unto it."}], "2:3": [{"ref": "2 Ne 12:3", "source": "bom", "text": "And many people shall go and say, Come ye, and let us go up to the mountain of the Lord, to the house of the God of Jacob; and he will teach us of his ways, and we will walk in his paths; for out of Zion shall go forth the law, and the word of the Lord from Jerusalem."}, {"ref": "Micah 4:2", "source": "ot", "text": "And many nations shall come, and say, Come, and let us go up to the mountain of the LORD, and to the house of the God of Jacob; and he will teach us of his ways, and we will walk in his paths: for the law shall go forth of Zion, and the word of the LORD from Jerusalem."}], "2:4": [{"ref": "Joel 3:10", "source": "ot", "text": "Beat your plowshares into swords, and your pruninghooks into spears: let the weak say, I am strong."}, {"ref": "Micah 4:3", "source": "ot", "text": "And he shall judge among many people, and rebuke strong nations afar off; and they shall beat their swords into plowshares, and their spears into pruninghooks: nation shall not lift up a sword against nation, neither shall they learn war any more."}, {"ref": "2 Ne 12:4", "source": "bom", "text": "And he shall judge among the nations, and shall rebuke many people: and they shall beat their swords into plow-shares, and their spears into pruning-hooks—nation shall not lift up sword against nation, neither shall they learn war any more."}], "2:5": [{"ref": "2 Ne 12:5", "source": "bom", "text": "O house of Jacob, come ye and let us walk in the light of the Lord; yea, come, for ye have all gone astray, every one to his wicked ways."}], "2:10": [{"ref": "2 Ne 12:10", "source": "bom", "text": "O ye wicked ones, enter into the rock, and hide thee in the dust, for the fear of the Lord and the glory of his majesty shall smite thee."}, {"ref": "Rev 6:15", "source": "nt", "text": "And the kings of the earth, and the great men, and the rich men, and the chief captains, and the mighty men, and every bondman, and every free man, hid themselves in the dens and in the rocks of the mountains;"}], "2:12": [{"ref": "2 Ne 12:12", "source": "bom", "text": "For the day of the Lord of Hosts soon cometh upon all nations, yea, upon every one; yea, upon the proud and lofty, and upon every one who is lifted up, and he shall be brought low."}], "2:19": [{"ref": "2 Ne 12:19", "source": "bom", "text": "And they shall go into the holes of the rocks, and into the caves of the earth, for the fear of the Lord shall come upon them and the glory of his majesty shall smite them, when he ariseth to shake terribly the earth."}, {"ref": "Rev 6:15", "source": "nt", "text": "And the kings of the earth, and the great men, and the rich men, and the chief captains, and the mighty men, and every bondman, and every free man, hid themselves in the dens and in the rocks of the mountains;"}], "3:1": [{"ref": "2 Ne 13:1", "source": "bom", "text": "For behold, the Lord, the Lord of Hosts, doth take away from Jerusalem, and from Judah, the stay and the staff, the whole staff of bread, and the whole stay of water—"}], "3:9": [{"ref": "Gen 13:13", "source": "ot", "text": "But the men of Sodom were wicked and sinners before the LORD exceedingly."}, {"ref": "2 Ne 13:9", "source": "bom", "text": "The show of their countenance doth witness against them, and doth declare their sin to be even as Sodom, and they cannot hide it. Wo unto their souls, for they have rewarded evil unto themselves!"}], "3:14": [{"ref": "2 Ne 13:14", "source": "bom", "text": "The Lord will enter into judgment with the ancients of his people and the princes thereof; for ye have eaten up the vineyard and the spoil of the poor in your houses."}], "3:16": [{"ref": "2 Ne 13:16", "source": "bom", "text": "Moreover, the Lord saith: Because the daughters of Zion are haughty, and walk with stretched-forth necks and wanton eyes, walking and mincing as they go, and making a tinkling with their feet—"}], "4:1": [{"ref": "2 Ne 14:1", "source": "bom", "text": "And in that day, seven women shall take hold of one man, saying: We will eat our own bread, and wear our own apparel; only let us be called by thy name to take away our reproach."}], "4:2": [{"ref": "Jer 23:5", "source": "ot", "text": "Behold, the days come, saith the LORD, that I will raise unto David a righteous Branch, and a King shall reign and prosper, and shall execute judgment and justice in the earth."}, {"ref": "Zech 3:8", "source": "ot", "text": "Hear now, O Joshua the high priest, thou, and thy fellows that sit before thee: for they are men wondered at: for, behold, I will bring forth my servant the BRANCH."}, {"ref": "2 Ne 14:2", "source": "bom", "text": "In that day shall the branch of the Lord be beautiful and glorious; the fruit of the earth excellent and comely to them that are escaped of Israel."}], "4:3": [{"ref": "2 Ne 14:3", "source": "bom", "text": "And it shall come to pass, they that are left in Zion and remain in Jerusalem shall be called holy, every one that is written among the living in Jerusalem—"}], "4:4": [{"ref": "Mal 3:2-3", "source": "ot", "text": "But who may abide the day of his coming? and who shall stand when he appeareth? for he is like a refiner's fire, and like fullers' soap:"}, {"ref": "2 Ne 14:4", "source": "bom", "text": "When the Lord shall have washed away the filth of the daughters of Zion, and shall have purged the blood of Jerusalem from the midst thereof by the spirit of judgment and by the spirit of burning."}], "4:5": [{"ref": "Ex 13:21-22", "source": "ot", "text": "And the LORD went before them by day in a pillar of a cloud, to lead them the way; and by night in a pillar of fire, to give them light; to go by day and night:"}, {"ref": "2 Ne 14:5", "source": "bom", "text": "And the Lord will create upon every dwelling-place of mount Zion, and upon her assemblies, a cloud and smoke by day and the shining of a flaming fire by night; for upon all the glory of Zion shall be a defence."}], "4:6": [{"ref": "2 Ne 14:6", "source": "bom", "text": "And there shall be a tabernacle for a shadow in the daytime from the heat, and for a place of refuge, and a covert from storm and from rain."}], "5:1": [{"ref": "2 Ne 15:1", "source": "bom", "text": "And then will I sing to my well-beloved a song of my beloved, touching his vineyard. My well-beloved hath a vineyard in a very fruitful hill."}, {"ref": "Matt 21:33", "source": "nt", "text": "Hear another parable: There was a certain householder, which planted a vineyard, and hedged it round about, and digged a winepress in it, and built a tower, and let it out to husbandmen, and went into a far country:"}], "5:7": [{"ref": "2 Ne 15:7", "source": "bom", "text": "For the vineyard of the Lord of Hosts is the house of Israel, and the men of Judah his pleasant plant; and he looked for judgment, and behold, oppression; for righteousness, but behold, a cry."}], "5:8": [{"ref": "2 Ne 15:8", "source": "bom", "text": "Wo unto them that join house to house, till there can be no place, that they may be placed alone in the midst of the earth!"}, {"ref": "Micah 2:2", "source": "ot", "text": "And they covet fields, and take them by violence; and houses, and take them away: so they oppress a man and his house, even a man and his heritage."}], "5:20": [{"ref": "2 Ne 15:20", "source": "bom", "text": "Wo unto them that call evil good, and good evil, that put darkness for light, and light for darkness, that put bitter for sweet, and sweet for bitter!"}, {"ref": "Moro 7:14", "source": "bom", "text": "Wherefore, take heed, my beloved brethren, that ye do not judge that which is evil to be of God, or that which is good and of God to be of the devil."}], "5:25": [{"ref": "2 Ne 15:25", "source": "bom", "text": "Therefore, is the anger of the Lord kindled against his people, and he hath stretched forth his hand against them, and hath smitten them; and the hills did tremble, and their carcasses were torn in the midst of the streets. For all this his anger is not turned away, but his hand is stretched out still."}], "5:26": [{"ref": "2 Ne 15:26", "source": "bom", "text": "And he will lift up an ensign to the nations from far, and will hiss unto them from the end of the earth; and behold, they shall come with speed swiftly; none shall be weary nor stumble among them."}], "6:1": [{"ref": "2 Ne 16:1", "source": "bom", "text": "In the year that king Uzziah died, I saw also the Lord sitting upon a throne, high and lifted up, and his train filled the temple."}, {"ref": "John 12:41", "source": "nt", "text": "These things said Esaias, when he saw his glory, and spake of him."}, {"ref": "Rev 4:2", "source": "nt", "text": "And immediately I was in the spirit: and, behold, a throne was set in heaven, and one sat on the throne."}], "6:2": [{"ref": "2 Ne 16:2", "source": "bom", "text": "Above it stood the seraphim; each one had six wings; with twain he covered his face, and with twain he covered his feet, and with twain he did fly."}], "6:3": [{"ref": "2 Ne 16:3", "source": "bom", "text": "And one cried unto another, and said: Holy, holy, holy, is the Lord of Hosts; the whole earth is full of his glory."}, {"ref": "Rev 4:8", "source": "nt", "text": "And the four beasts had each of them six wings about him; and they were full of eyes within: and they rest not day and night, saying, Holy, holy, holy, Lord God Almighty, which was, and is, and is to come."}], "6:5": [{"ref": "2 Ne 16:5", "source": "bom", "text": "Then said I: Wo is unto me! for I am undone; because I am a man of unclean lips; and I dwell in the midst of a people of unclean lips; for mine eyes have seen the King, the Lord of Hosts."}, {"ref": "Ex 33:20", "source": "ot", "text": "And he said, Thou canst not see my face: for there shall no man see me, and live."}], "6:6": [{"ref": "2 Ne 16:6", "source": "bom", "text": "Then flew one of the seraphim unto me, having a live coal in his hand, which he had taken with the tongs from off the altar;"}], "6:8": [{"ref": "2 Ne 16:8", "source": "bom", "text": "Also I heard the voice of the Lord, saying: Whom shall I send, and who will go for us? Then I said: Here am I; send me."}], "6:9": [{"ref": "2 Ne 16:9", "source": "bom", "text": "And he said: Go and tell this people—Hear ye indeed, but they understood not; and see ye indeed, but they perceived not."}, {"ref": "Matt 13:14", "source": "nt", "text": "And in them is fulfilled the prophecy of Esaias, which saith, By hearing ye shall hear, and shall not understand; and seeing ye shall see, and shall not perceive:"}, {"ref": "Acts 28:26", "source": "nt", "text": "Saying, Go unto this people, and say, Hearing ye shall hear, and shall not understand; and seeing ye shall see, and not perceive:"}], "6:10": [{"ref": "2 Ne 16:10", "source": "bom", "text": "Make the heart of this people fat, and make their ears heavy, and shut their eyes—lest they see with their eyes, and hear with their ears, and understand with their heart, and be converted and be healed."}, {"ref": "Mark 4:12", "source": "nt", "text": "That seeing they may see, and not perceive; and hearing they may hear, and not understand; lest at any time they should be converted, and their sins should be forgiven them."}], "7:3": [{"ref": "2 Ne 17:3", "source": "bom", "text": "Then said the Lord unto Isaiah: Go forth now to meet Ahaz, thou and Shearjashub thy son, at the end of the conduit of the upper pool in the highway of the fuller's field;"}], "7:14": [{"ref": "2 Ne 17:14", "source": "bom", "text": "Therefore, the Lord himself shall give you a sign—Behold, a virgin shall conceive, and shall bear a son, and shall call his name Immanuel."}, {"ref": "Matt 1:23", "source": "nt", "text": "Behold, a virgin shall be with child, and shall bring forth a son, and they shall call his name Emmanuel, which being interpreted is, God with us."}, {"ref": "Luke 1:31", "source": "nt", "text": "And, behold, thou shalt conceive in thy womb, and bring forth a son, and shalt call his name JESUS."}], "8:1": [{"ref": "2 Ne 18:1", "source": "bom", "text": "Moreover, the word of the Lord said unto me: Take thee a great roll, and write in it with a man's pen, concerning Maher-shalal-hash-baz."}], "8:14": [{"ref": "2 Ne 18:14", "source": "bom", "text": "And he shall be for a sanctuary; but for a stone of stumbling, and for a rock of offense to both the houses of Israel, for a gin and a snare to the inhabitants of Jerusalem."}, {"ref": "Rom 9:33", "source": "nt", "text": "As it is written, Behold, I lay in Sion a stumblingstone and rock of offence: and whosoever believeth on him shall not be ashamed."}, {"ref": "1 Pet 2:8", "source": "nt", "text": "And a stone of stumbling, and a rock of offence, even to them which stumble at the word, being disobedient: whereunto also they were appointed."}], "8:16": [{"ref": "2 Ne 18:16", "source": "bom", "text": "Bind up the testimony, seal the law among my disciples."}], "8:18": [{"ref": "2 Ne 18:18", "source": "bom", "text": "Behold, I and the children whom the Lord hath given me are for signs and for wonders in Israel from the Lord of Hosts, which dwelleth in Mount Zion."}, {"ref": "Heb 2:13", "source": "nt", "text": "And again, I will put my trust in him. And again, Behold I and the children which God hath given me."}], "8:20": [{"ref": "2 Ne 18:20", "source": "bom", "text": "To the law and to the testimony; and if they speak not according to this word, it is because there is no light in them."}], "9:1": [{"ref": "2 Ne 19:1", "source": "bom", "text": "Nevertheless, the dimness shall not be such as was in her vexation, when at first he lightly afflicted the land of Zebulun, and the land of Naphtali, and afterwards did more grievously afflict by the way of the Red Sea beyond Jordan in Galilee of the nations."}, {"ref": "Matt 4:14-16", "source": "nt", "text": "That it might be fulfilled which was spoken by Esaias the prophet, saying,"}], "9:2": [{"ref": "2 Ne 19:2", "source": "bom", "text": "The people that walked in darkness have seen a great light; they that dwell in the land of the shadow of death, upon them hath the light shined."}, {"ref": "Matt 4:16", "source": "nt", "text": "The people which sat in darkness saw great light; and to them which sat in the region and shadow of death light is sprung up."}], "9:6": [{"ref": "2 Ne 19:6", "source": "bom", "text": "For unto us a child is born, unto us a son is given; and the government shall be upon his shoulder; and his name shall be called, Wonderful, Counselor, The Mighty God, The Everlasting Father, The Prince of Peace."}, {"ref": "Luke 1:32-33", "source": "nt", "text": "He shall be great, and shall be called the Son of the Highest: and the Lord God shall give unto him the throne of his father David:"}, {"ref": "John 1:1", "source": "nt", "text": "In the beginning was the Word, and the Word was with God, and the Word was God."}], "9:7": [{"ref": "2 Ne 19:7", "source": "bom", "text": "Of the increase of government and peace there is no end, upon the throne of David, and upon his kingdom to order it, and to establish it with judgment and with justice from henceforth, even forever. The zeal of the Lord of Hosts will perform this."}, {"ref": "Luke 1:32-33", "source": "nt", "text": "He shall be great, and shall be called the Son of the Highest: and the Lord God shall give unto him the throne of his father David:"}], "9:12": [{"ref": "2 Ne 19:12", "source": "bom", "text": "The Syrians before and the Philistines behind; and they shall devour Israel with open mouth. For all this his anger is not turned away, but his hand is stretched out still."}], "9:17": [{"ref": "2 Ne 19:17", "source": "bom", "text": "Therefore the Lord shall have no joy in their young men, neither shall have mercy on their fatherless and widows; for every one of them is a hypocrite and an evildoer, and every mouth speaketh folly. For all this his anger is not turned away, but his hand is stretched out still."}], "9:21": [{"ref": "2 Ne 19:21", "source": "bom", "text": "Manasseh, Ephraim; and Ephraim, Manasseh; they together shall be against Judah. For all this his anger is not turned away, but his hand is stretched out still."}], "10:3": [{"ref": "2 Ne 20:3", "source": "bom", "text": "And what will ye do in the day of visitation, and in the desolation which shall come from far? to whom will ye flee for help? and where will ye leave your glory?"}], "10:5": [{"ref": "2 Ne 20:5", "source": "bom", "text": "O Assyrian, the rod of mine anger, and the staff in their hand is their indignation."}], "10:12": [{"ref": "2 Ne 20:12", "source": "bom", "text": "Wherefore it shall come to pass that when the Lord hath performed his whole work upon Mount Zion and upon Jerusalem, I will punish the fruit of the stout heart of the king of Assyria, and the glory of his high looks."}], "10:15": [{"ref": "2 Ne 20:15", "source": "bom", "text": "Shall the ax boast itself against him that heweth therewith? Shall the saw magnify itself against him that shaketh it? As if the rod should shake itself against them that lift it up, or as if the staff should lift up itself as if it were no wood!"}], "10:20": [{"ref": "2 Ne 20:20", "source": "bom", "text": "And it shall come to pass in that day, that the remnant of Israel, and such as are escaped of the house of Jacob, shall no more again stay upon him that smote them, but shall stay upon the Lord, the Holy One of Israel, in truth."}], "10:22": [{"ref": "2 Ne 20:22", "source": "bom", "text": "For though thy people Israel be as the sand of the sea, yet a remnant of them shall return; the consumption decreed shall overflow with righteousness."}, {"ref": "Rom 9:27-28", "source": "nt", "text": "Esaias also crieth concerning Israel, Though the number of the children of Israel be as the sand of the sea, a remnant shall be saved:"}], "10:24": [{"ref": "2 Ne 20:24", "source": "bom", "text": "Therefore, thus saith the Lord God of Hosts: O my people that dwellest in Zion, be not afraid of the Assyrian; he shall smite thee with a rod, and shall lift up his staff against thee, after the manner of Egypt."}], "10:27": [{"ref": "2 Ne 20:27", "source": "bom", "text": "And it shall come to pass in that day that his burden shall be taken away from off thy shoulder, and his yoke from off thy neck, and the yoke shall be destroyed because of the anointing."}], "10:34": [{"ref": "2 Ne 20:34", "source": "bom", "text": "And he shall cut down the thickets of the forests with iron, and Lebanon shall fall by a mighty one."}], "11:1": [{"ref": "2 Ne 21:1", "source": "bom", "text": "And there shall come forth a rod out of the stem of Jesse, and a branch shall grow out of his roots."}, {"ref": "D&C 113:1-2", "source": "dc", "text": "Who is the Stem of Jesse spoken of in the 1st, 2d, 3d, 4th, and 5th verses of the 11th chapter of Isaiah?"}, {"ref": "Rev 5:5", "source": "nt", "text": "And one of the elders saith unto me, Weep not: behold, the Lion of the tribe of Juda, the Root of David, hath prevailed to open the book, and to loose the seven seals thereof."}, {"ref": "Jer 23:5", "source": "ot", "text": "Behold, the days come, saith the LORD, that I will raise unto David a righteous Branch, and a King shall reign and prosper, and shall execute judgment and justice in the earth."}], "11:2": [{"ref": "2 Ne 21:2", "source": "bom", "text": "And the Spirit of the Lord shall rest upon him, the spirit of wisdom and understanding, the spirit of counsel and might, the spirit of knowledge and of the fear of the Lord;"}], "11:4": [{"ref": "2 Ne 21:4", "source": "bom", "text": "But with righteousness shall he judge the poor, and reprove with equity for the meek of the earth; and he shall smite the earth with the rod of his mouth, and with the breath of his lips shall he slay the wicked."}, {"ref": "2 Thes 2:8", "source": "nt", "text": "And then shall that Wicked be revealed, whom the Lord shall consume with the spirit of his mouth, and shall destroy with the brightness of his coming:"}], "11:5": [{"ref": "2 Ne 21:5", "source": "bom", "text": "And righteousness shall be the girdle of his loins, and faithfulness the girdle of his reins."}], "11:6": [{"ref": "2 Ne 21:6", "source": "bom", "text": "The wolf also shall dwell with the lamb, and the leopard shall lie down with the kid, and the calf and the young lion and fatling together; and a little child shall lead them."}, {"ref": "D&C 101:26", "source": "dc", "text": "And in that day the enmity of man, and the enmity of beasts, yea, the enmity of all flesh, shall cease from before my face."}], "11:9": [{"ref": "2 Ne 21:9", "source": "bom", "text": "They shall not hurt nor destroy in all my holy mountain, for the earth shall be full of the knowledge of the Lord, as the waters cover the sea."}, {"ref": "Hab 2:14", "source": "ot", "text": "For the earth shall be filled with the knowledge of the glory of the LORD, as the waters cover the sea."}], "11:10": [{"ref": "2 Ne 21:10", "source": "bom", "text": "And in that day there shall be a root of Jesse, which shall stand for an ensign of the people; to it shall the Gentiles seek; and his rest shall be glorious."}, {"ref": "D&C 113:5-6", "source": "dc", "text": "What is the root of Jesse spoken of in the 10th verse of the 11th chapter?"}, {"ref": "Rom 15:12", "source": "nt", "text": "And again, Esaias saith, There shall be a root of Jesse, and he that shall rise to reign over the Gentiles; in him shall the Gentiles trust."}], "11:11": [{"ref": "2 Ne 21:11", "source": "bom", "text": "And it shall come to pass in that day that the Lord shall set his hand again the second time to recover the remnant of his people which shall be left, from Assyria, and from Egypt, and from Pathros, and from Cush, and from Elam, and from Shinar, and from Hamath, and from the islands of the sea."}, {"ref": "D&C 45:24-25", "source": "dc", "text": "And this I have told you concerning Jerusalem; and when that day shall come, shall a remnant be scattered among all nations;"}], "11:12": [{"ref": "2 Ne 21:12", "source": "bom", "text": "And he shall set up an ensign for the nations, and shall assemble the outcasts of Israel, and gather together the dispersed of Judah from the four corners of the earth."}], "11:15": [{"ref": "2 Ne 21:15", "source": "bom", "text": "And the Lord shall utterly destroy the tongue of the Egyptian sea; and with his mighty wind he shall shake his hand over the river, and shall smite it in the seven streams, and make men go over dry shod."}], "11:16": [{"ref": "2 Ne 21:16", "source": "bom", "text": "And there shall be a highway for the remnant of his people which shall be left, from Assyria, like as it was to Israel in the day that he came up out of the land of Egypt."}], "12:1": [{"ref": "2 Ne 22:1", "source": "bom", "text": "And in that day thou shalt say: O Lord, I will praise thee; though thou wast angry with me thine anger is turned away, and thou comfortedst me."}], "12:2": [{"ref": "2 Ne 22:2", "source": "bom", "text": "Behold, God is my salvation; I will trust, and not be afraid; for the Lord JEHOVAH is my strength and my song; he also has become my salvation."}, {"ref": "Ex 15:2", "source": "ot", "text": "The LORD is my strength and song, and he is become my salvation: he is my God, and I will prepare him an habitation; my father's God, and I will exalt him."}, {"ref": "Ps 118:14", "source": "ot", "text": "The LORD is my strength and song, and is become my salvation."}], "12:3": [{"ref": "2 Ne 22:3", "source": "bom", "text": "Therefore, with joy shall ye draw water out of the wells of salvation."}, {"ref": "John 4:14", "source": "nt", "text": "But whosoever drinketh of the water that I shall give him shall never thirst; but the water that I shall give him shall be in him a well of water springing up into everlasting life."}, {"ref": "7:37", "source": "ot"}], "12:4": [{"ref": "2 Ne 22:4", "source": "bom", "text": "And in that day shall ye say: Praise the Lord, call upon his name, declare his doings among the people, make mention that his name is exalted."}], "12:6": [{"ref": "2 Ne 22:6", "source": "bom", "text": "Cry out and shout, thou inhabitant of Zion; for great is the Holy One of Israel in the midst of thee."}], "13:1": [{"ref": "2 Ne 23:1", "source": "bom", "text": "The burden of Babylon, which Isaiah the son of Amoz did see."}], "13:6": [{"ref": "2 Ne 23:6", "source": "bom", "text": "Howl ye, for the day of the Lord is at hand; it shall come as a destruction from the Almighty."}, {"ref": "Joel 1:15", "source": "ot", "text": "Alas for the day! for the day of the LORD is at hand, and as a destruction from the Almighty shall it come."}], "13:9": [{"ref": "2 Ne 23:9", "source": "bom", "text": "Behold, the day of the Lord cometh, cruel both with wrath and fierce anger, to lay the land desolate; and he shall destroy the sinners thereof out of it."}], "13:10": [{"ref": "2 Ne 23:10", "source": "bom", "text": "For the stars of heaven and the constellations thereof shall not give their light; the sun shall be darkened in his going forth, and the moon shall not cause her light to shine."}, {"ref": "Joel 2:10", "source": "ot", "text": "The earth shall quake before them; the heavens shall tremble: the sun and the moon shall be dark, and the stars shall withdraw their shining:"}, {"ref": "Matt 24:29", "source": "nt", "text": "Immediately after the tribulation of those days shall the sun be darkened, and the moon shall not give her light, and the stars shall fall from heaven, and the powers of the heavens shall be shaken:"}], "13:11": [{"ref": "2 Ne 23:11", "source": "bom", "text": "And I will punish the world for evil, and the wicked for their iniquity; I will cause the arrogancy of the proud to cease, and will lay down the haughtiness of the terrible."}], "13:19": [{"ref": "2 Ne 23:19", "source": "bom", "text": "And Babylon, the glory of kingdoms, the beauty of the Chaldees' excellency, shall be as when God overthrew Sodom and Gomorrah."}, {"ref": "Gen 19:24-25", "source": "ot", "text": "Then the LORD rained upon Sodom and upon Gomorrah brimstone and fire from the LORD out of heaven;"}], "13:22": [{"ref": "2 Ne 23:22", "source": "bom", "text": "And the wild beasts of the islands shall cry in their desolate houses, and dragons in their pleasant palaces; and her time is near to come, and her day shall not be prolonged. For I will destroy her speedily; yea, for I will be merciful unto my people, but the wicked shall perish."}], "14:1": [{"ref": "2 Ne 24:1", "source": "bom", "text": "For the Lord will have mercy on Jacob, and will yet choose Israel, and set them in their own land; and the strangers shall be joined with them, and they shall cleave to the house of Jacob."}], "14:4": [{"ref": "2 Ne 24:4", "source": "bom", "text": "And it shall come to pass in that day, that thou shalt take up this proverb against the king of Babylon, and say: How hath the oppressor ceased, the golden city ceased!"}], "14:12": [{"ref": "2 Ne 24:12", "source": "bom", "text": "How art thou fallen from heaven, O Lucifer, son of the morning! Art thou cut down to the ground, which did weaken the nations!"}, {"ref": "Luke 10:18", "source": "nt", "text": "And he said unto them, I beheld Satan as lightning fall from heaven."}, {"ref": "D&C 76:25-27", "source": "dc", "text": "And this we saw also, and bear record, that an angel of God who was in authority in the presence of God, who rebelled against the Only Begotten Son whom the Father loved and who was in the bosom of the Father, was thrust down from the presence of God and the Son,"}], "14:13": [{"ref": "2 Ne 24:13", "source": "bom", "text": "For thou hast said in thy heart: I will ascend into heaven, I will exalt my throne above the stars of God; I will sit also upon the mount of the congregation, in the sides of the north;"}], "14:24": [{"ref": "2 Ne 24:24", "source": "bom", "text": "The Lord of Hosts hath sworn, saying: Surely as I have thought, so shall it come to pass; and as I have purposed, so shall it stand—"}], "14:27": [{"ref": "2 Ne 24:27", "source": "bom", "text": "For the Lord of Hosts hath purposed, and who shall disannul? And his hand is stretched out, and who shall turn it back?"}], "14:32": [{"ref": "2 Ne 24:32", "source": "bom", "text": "What shall then answer the messengers of the nations? That the Lord hath founded Zion, and the poor of his people shall trust in it."}], "22:20": [{"ref": "D&C 113:7-8", "source": "dc", "text": "Questions by Elias Higbee: What is meant by the command in Isaiah, 52d chapter, 1st verse, which saith: Put on thy strength, O Zion—and what people had Isaiah reference to?"}], "22:22": [{"ref": "Rev 3:7", "source": "nt", "text": "And to the angel of the church in Philadelphia write; These things saith he that is holy, he that is true, he that hath the key of David, he that openeth, and no man shutteth; and shutteth, and no man openeth;"}, {"ref": "D&C 113:5-6", "source": "dc", "text": "What is the root of Jesse spoken of in the 10th verse of the 11th chapter?"}], "22:23": [{"ref": "Ezra 9:8", "source": "ot", "text": "And now for a little space grace hath been shewed from the LORD our God, to leave us a remnant to escape, and to give us a nail in his holy place, that our God may lighten our eyes, and give us a little reviving in our bondage."}], "25:6": [{"ref": "D&C 58:8-12", "source": "dc", "text": "And also that a feast of fat things might be prepared for the poor; yea, a feast of fat things, of wine on the lees well refined, that the earth may know that the mouths of the prophets shall not fail;"}], "25:8": [{"ref": "Rev 7:17", "source": "nt", "text": "For the Lamb which is in the midst of the throne shall feed them, and shall lead them unto living fountains of waters: and God shall wipe away all tears from their eyes."}, {"ref": "Rev 21:4", "source": "nt", "text": "And God shall wipe away all tears from their eyes; and there shall be no more death, neither sorrow, nor crying, neither shall there be any more pain: for the former things are passed away."}, {"ref": "1 Cor 15:54", "source": "nt", "text": "So when this corruptible shall have put on incorruption, and this mortal shall have put on immortality, then shall be brought to pass the saying that is written, Death is swallowed up in victory."}], "25:9": [{"ref": "Ps 33:21", "source": "ot", "text": "For our heart shall rejoice in him, because we have trusted in his holy name."}], "28:10": [{"ref": "2 Ne 28:30", "source": "bom", "text": "For behold, thus saith the Lord God: I will give unto the children of men line upon line, precept upon precept, here a little and there a little; and blessed are those who hearken unto my precepts, and lend an ear unto my counsel, for they shall learn wisdom; for unto him that receiveth I will give more; and from them that shall say, We have enough, from them shall be taken away even that which they have."}, {"ref": "D&C 98:12", "source": "dc", "text": "For he will give unto the faithful line upon line, precept upon precept; and I will try you and prove you herewith."}], "28:16": [{"ref": "Ps 118:22", "source": "ot", "text": "The stone which the builders refused is become the head stone of the corner."}, {"ref": "Matt 21:42", "source": "nt", "text": "Jesus saith unto them, Did ye never read in the scriptures, The stone which the builders rejected, the same is become the head of the corner: this is the Lord's doing, and it is marvellous in our eyes?"}, {"ref": "Acts 4:11", "source": "nt", "text": "This is the stone which was set at nought of you builders, which is become the head of the corner."}, {"ref": "1 Pet 2:6", "source": "nt", "text": "Wherefore also it is contained in the scripture, Behold, I lay in Sion a chief corner stone, elect, precious: and he that believeth on him shall not be confounded."}], "29:4": [{"ref": "2 Ne 26:16", "source": "bom", "text": "For those who shall be destroyed shall speak unto them out of the ground, and their speech shall be low out of the dust, and their voice shall be as one that hath a familiar spirit; for the Lord God will give unto him power, that he may whisper concerning them, even as it were out of the ground; and their speech shall whisper out of the dust."}, {"ref": "2 Ne 33:13", "source": "bom", "text": "And now, my beloved brethren, all those who are of the house of Israel, and all ye ends of the earth, I speak unto you as the voice of one crying from the dust: Farewell until that great day shall come."}], "29:11": [{"ref": "2 Ne 27:6-26", "source": "bom", "text": "And it shall come to pass that the Lord God shall bring forth unto you the words of a book, and they shall be the words of them which have slumbered."}], "29:12": [{"ref": "2 Ne 27:15-20", "source": "bom", "text": "But behold, it shall come to pass that the Lord God shall say unto him to whom he shall deliver the book: Take these words which are not sealed and deliver them to another, that he may show them unto the learned, saying: Read this, I pray thee. And the learned shall say: Bring hither the book, and I will read them."}, {"ref": "JS-H 1:63-65", "source": "pgp", "text": "Sometime in this month of February, the aforementioned Mr. Martin Harris came to our place, got the characters which I had drawn off the plates, and started with them to the city of New York. For what took place relative to him and the characters, I refer to his own account of the circumstances, as he related them to me after his return, which was as follows:"}], "29:13": [{"ref": "Matt 15:8-9", "source": "nt", "text": "This people draweth nigh unto me with their mouth, and honoureth me with their lips; but their heart is far from me."}, {"ref": "JS-H 1:19", "source": "pgp", "text": "I was answered that I must join none of them, for they were all wrong; and the Personage who addressed me said that all their creeds were an abomination in his sight; that those professors were all corrupt; that: \"they draw near to me with their lips, but their hearts are far from me, they teach for doctrines the commandments of men, having a form of godliness, but they deny the power thereof.\""}], "29:14": [{"ref": "2 Ne 25:17", "source": "bom", "text": "And the Lord will set his hand again the second time to restore his people from their lost and fallen state. Wherefore, he will proceed to do a marvelous work and a wonder among the children of men."}, {"ref": "2 Ne 27:26", "source": "bom", "text": "Therefore, I will proceed to do a marvelous work among this people, yea, a marvelous work and a wonder, for the wisdom of their wise and learned shall perish, and the understanding of their prudent shall be hid."}], "29:18": [{"ref": "2 Ne 27:29", "source": "bom", "text": "And in that day shall the deaf hear the words of the book, and the eyes of the blind shall see out of obscurity and out of darkness."}], "35:1": [{"ref": "D&C 117:7", "source": "dc", "text": "Therefore, will I not make solitary places to bud and to blossom, and to bring forth in abundance? saith the Lord."}], "35:5": [{"ref": "Matt 11:5", "source": "nt", "text": "The blind receive their sight, and the lame walk, the lepers are cleansed, and the deaf hear, the dead are raised up, and the poor have the gospel preached to them."}], "35:8": [{"ref": "D&C 45:66-67", "source": "dc", "text": "And it shall be called the New Jerusalem, a land of peace, a city of refuge, a place of safety for the saints of the Most High God;"}], "35:10": [{"ref": "D&C 66:11", "source": "dc", "text": "Keep these sayings, for they are true and faithful; and thou shalt magnify thine office, and push many people to Zion with songs of everlasting joy upon their heads."}, {"ref": "Rev 21:4", "source": "nt", "text": "And God shall wipe away all tears from their eyes; and there shall be no more death, neither sorrow, nor crying, neither shall there be any more pain: for the former things are passed away."}], "40:3": [{"ref": "Matt 3:3", "source": "nt", "text": "For this is he that was spoken of by the prophet Esaias, saying, The voice of one crying in the wilderness, Prepare ye the way of the Lord, make his paths straight."}, {"ref": "Mark 1:3", "source": "nt", "text": "The voice of one crying in the wilderness, Prepare ye the way of the Lord, make his paths straight."}, {"ref": "Luke 3:4", "source": "nt", "text": "As it is written in the book of the words of Esaias the prophet, saying, The voice of one crying in the wilderness, Prepare ye the way of the Lord, make his paths straight."}, {"ref": "John 1:23", "source": "nt", "text": "He said, I am the voice of one crying in the wilderness, Make straight the way of the Lord, as said the prophet Esaias."}, {"ref": "D&C 33:10", "source": "dc", "text": "Yea, open your mouths and they shall be filled, saying: Repent, repent, and prepare ye the way of the Lord, and make his paths straight; for the kingdom of heaven is at hand;"}], "40:5": [{"ref": "Luke 3:6", "source": "nt", "text": "And all flesh shall see the salvation of God."}], "40:8": [{"ref": "1 Pet 1:25", "source": "nt", "text": "But the word of the Lord endureth for ever. And this is the word which by the gospel is preached unto you."}], "40:11": [{"ref": "Ezek 34:23", "source": "ot", "text": "And I will set up one shepherd over them, and he shall feed them, even my servant David; he shall feed them, and he shall be their shepherd."}, {"ref": "John 10:11", "source": "nt", "text": "I am the good shepherd: the good shepherd giveth his life for the sheep."}, {"ref": "Heb 13:20", "source": "nt", "text": "Now the God of peace, that brought again from the dead our Lord Jesus, that great shepherd of the sheep, through the blood of the everlasting covenant,"}, {"ref": "1 Pet 5:4", "source": "nt", "text": "And when the chief Shepherd shall appear, ye shall receive a crown of glory that fadeth not away."}], "40:13": [{"ref": "Rom 11:34", "source": "nt", "text": "For who hath known the mind of the Lord? or who hath been his counsellor?"}, {"ref": "1 Cor 2:16", "source": "nt", "text": "For who hath known the mind of the Lord, that he may instruct him? But we have the mind of Christ."}], "40:18": [{"ref": "Acts 17:29", "source": "nt", "text": "Forasmuch then as we are the offspring of God, we ought not to think that the Godhead is like unto gold, or silver, or stone, graven by art and man's device."}], "40:28": [{"ref": "Ps 147:5", "source": "ot", "text": "Great is our Lord, and of great power: his understanding is infinite."}], "40:31": [{"ref": "D&C 89:18-20", "source": "dc", "text": "And all saints who remember to keep and do these sayings, walking in obedience to the commandments, shall receive health in their navel and marrow to their bones;"}], "41:8": [{"ref": "James 2:23", "source": "nt", "text": "And the scripture was fulfilled which saith, Abraham believed God, and it was imputed unto him for righteousness: and he was called the Friend of God."}, {"ref": "2 Chr 20:7", "source": "ot", "text": "Art not thou our God, who didst drive out the inhabitants of this land before thy people Israel, and gavest it to the seed of Abraham thy friend for ever?"}], "41:10": [{"ref": "Deut 31:6", "source": "ot", "text": "Be strong and of a good courage, fear not, nor be afraid of them: for the LORD thy God, he it is that doth go with thee; he will not fail thee, nor forsake thee."}, {"ref": "Josh 1:9", "source": "ot", "text": "Have not I commanded thee? Be strong and of a good courage; be not afraid, neither be thou dismayed: for the LORD thy God is with thee whithersoever thou goest."}], "41:13": [{"ref": "Deut 31:6", "source": "ot", "text": "Be strong and of a good courage, fear not, nor be afraid of them: for the LORD thy God, he it is that doth go with thee; he will not fail thee, nor forsake thee."}], "41:14": [{"ref": "D&C 113:3-4", "source": "dc", "text": "What is the rod spoken of in the first verse of the 11th chapter of Isaiah, that should come of the Stem of Jesse?"}], "42:1": [{"ref": "Matt 3:17", "source": "nt", "text": "And lo a voice from heaven, saying, This is my beloved Son, in whom I am well pleased."}, {"ref": "Matt 12:18-21", "source": "nt", "text": "Behold my servant, whom I have chosen; my beloved, in whom my soul is well pleased: I will put my spirit upon him, and he shall shew judgment to the Gentiles."}, {"ref": "Mosiah 14:1", "source": "bom", "text": "Yea, even doth not Isaiah say: Who hath believed our report, and to whom is the arm of the Lord revealed?"}], "42:6": [{"ref": "Luke 2:32", "source": "nt", "text": "A light to lighten the Gentiles, and the glory of thy people Israel."}, {"ref": "Acts 13:47", "source": "nt", "text": "For so hath the Lord commanded us, saying, I have set thee to be a light of the Gentiles, that thou shouldest be for salvation unto the ends of the earth."}], "42:7": [{"ref": "Luke 4:18", "source": "nt", "text": "The Spirit of the Lord is upon me, because he hath anointed me to preach the gospel to the poor; he hath sent me to heal the brokenhearted, to preach deliverance to the captives, and recovering of sight to the blind, to set at liberty them that are bruised,"}], "42:8": [{"ref": "D&C 76:1", "source": "dc", "text": "Hear, O ye heavens, and give ear, O earth, and rejoice ye inhabitants thereof, for the Lord is God, and beside him there is no Savior."}], "42:10": [{"ref": "Ps 96:1", "source": "ot", "text": "O sing unto the LORD a new song: sing unto the LORD, all the earth."}, {"ref": "Rev 5:9", "source": "nt", "text": "And they sung a new song, saying, Thou art worthy to take the book, and to open the seals thereof: for thou wast slain, and hast redeemed us to God by thy blood out of every kindred, and tongue, and people, and nation;"}], "43:1": [{"ref": "D&C 18:10", "source": "dc", "text": "Remember the worth of souls is great in the sight of God;"}], "43:2": [{"ref": "Ps 66:12", "source": "ot", "text": "Thou hast caused men to ride over our heads; we went through fire and through water: but thou broughtest us out into a wealthy place."}], "43:3": [{"ref": "Ps 106:10", "source": "ot", "text": "And he saved them from the hand of him that hated them, and redeemed them from the hand of the enemy."}], "43:5": [{"ref": "Jer 30:10", "source": "ot", "text": "Therefore fear thou not, O my servant Jacob, saith the LORD; neither be dismayed, O Israel: for, lo, I will save thee from afar, and thy seed from the land of their captivity; and Jacob shall return, and shall be in rest, and be quiet, and none shall make him afraid."}], "43:7": [{"ref": "D&C 18:10", "source": "dc", "text": "Remember the worth of souls is great in the sight of God;"}], "43:10": [{"ref": "John 8:24", "source": "nt", "text": "I said therefore unto you, that ye shall die in your sins: for if ye believe not that I am he, ye shall die in your sins."}], "43:11": [{"ref": "Hosea 13:4", "source": "ot", "text": "Yet I am the LORD thy God from the land of Egypt, and thou shalt know no god but me: for there is no saviour beside me."}, {"ref": "Acts 4:12", "source": "nt", "text": "Neither is there salvation in any other: for there is none other name under heaven given among men, whereby we must be saved."}], "43:25": [{"ref": "Jer 31:34", "source": "ot", "text": "And they shall teach no more every man his neighbour, and every man his brother, saying, Know the LORD: for they shall all know me, from the least of them unto the greatest of them, saith the LORD: for I will forgive their iniquity, and I will remember their sin no more."}, {"ref": "D&C 58:42", "source": "dc", "text": "Behold, he who has repented of his sins, the same is forgiven, and I, the Lord, remember them no more."}], "44:3": [{"ref": "Joel 2:28-29", "source": "ot", "text": "And it shall come to pass afterward, that I will pour out my spirit upon all flesh; and your sons and your daughters shall prophesy, your old men shall dream dreams, your young men shall see visions:"}, {"ref": "Acts 2:17", "source": "nt", "text": "And it shall come to pass in the last days, saith God, I will pour out of my Spirit upon all flesh: and your sons and your daughters shall prophesy, and your young men shall see visions, and your old men shall dream dreams:"}], "44:6": [{"ref": "Rev 1:8", "source": "nt", "text": "I am Alpha and Omega, the beginning and the ending, saith the Lord, which is, and which was, and which is to come, the Almighty."}, {"ref": "Rev 22:13", "source": "nt", "text": "I am Alpha and Omega, the beginning and the end, the first and the last."}], "44:8": [{"ref": "Deut 32:4", "source": "ot", "text": "He is the Rock, his work is perfect: for all his ways are judgment: a God of truth and without iniquity, just and right is he."}], "44:22": [{"ref": "D&C 1:32", "source": "dc", "text": "Nevertheless, he that repents and does the commandments of the Lord shall be forgiven;"}], "44:28": [{"ref": "2 Chr 36:23", "source": "ot", "text": "Thus saith Cyrus king of Persia, All the kingdoms of the earth hath the LORD God of heaven given me; and he hath charged me to build him an house in Jerusalem, which is in Judah. Who is there among you of all his people? The LORD his God be with him, and let him go up."}, {"ref": "Ezra 1:1-2", "source": "ot", "text": "Now in the first year of Cyrus king of Persia, that the word of the LORD by the mouth of Jeremiah might be fulfilled, the LORD stirred up the spirit of Cyrus king of Persia, that he made a proclamation throughout all his kingdom, and put it also in writing, saying,"}], "45:1": [{"ref": "D&C 45:1", "source": "dc", "text": "Hearken, O ye people of my church, to whom the kingdom has been given; hearken ye and give ear to him who laid the foundation of the earth, who made the heavens and all the hosts thereof, and by whom all things were made which live, and move, and have a being."}], "45:5": [{"ref": "Deut 4:35", "source": "ot", "text": "Unto thee it was shewed, that thou mightest know that the LORD he is God; there is none else beside him."}], "45:18": [{"ref": "Moses 1:39", "source": "pgp", "text": "For behold, this is my work and my glory—to bring to pass the immortality and eternal life of man."}], "45:21": [{"ref": "Mark 12:32", "source": "nt", "text": "And the scribe said unto him, Well, Master, thou hast said the truth: for there is one God; and there is none other but he:"}], "45:22": [{"ref": "2 Ne 26:33", "source": "bom", "text": "For none of these iniquities come of the Lord; for he doeth that which is good among the children of men; and he doeth nothing save it be plain unto the children of men; and he inviteth them all to come unto him and partake of his goodness; and he denieth none that come unto him, black and white, bond and free, male and female; and he remembereth the heathen; and all are alike unto God, both Jew and Gentile."}, {"ref": "Alma 5:33", "source": "bom", "text": "Behold, he sendeth an invitation unto all men, for the arms of mercy are extended towards them, and he saith: Repent, and I will receive you."}], "45:23": [{"ref": "Rom 14:11", "source": "nt", "text": "For it is written, As I live, saith the Lord, every knee shall bow to me, and every tongue shall confess to God."}, {"ref": "Philip 2:10-11", "source": "nt", "text": "That at the name of Jesus every knee should bow, of things in heaven, and things in earth, and things under the earth;"}, {"ref": "Mosiah 27:31", "source": "bom", "text": "Yea, every knee shall bow, and every tongue confess before him. Yea, even at the last day, when all men shall stand to be judged of him, then shall they confess that he is God; then shall they confess, who live without God in the world, that the judgment of an everlasting punishment is just upon them; and they shall quake, and tremble, and shrink beneath the glance of his all-searching eye."}], "46:10": [{"ref": "D&C 38:2", "source": "dc", "text": "The same which knoweth all things, for all things are present before mine eyes;"}], "48:1": [{"ref": "1 Ne 20:1", "source": "bom", "text": "Hearken and hear this, O house of Jacob, who are called by the name of Israel, and are come forth out of the waters of Judah, or out of the waters of baptism, who swear by the name of the Lord, and make mention of the God of Israel, yet they swear not in truth nor in righteousness."}], "48:2": [{"ref": "1 Ne 20:2", "source": "bom", "text": "Nevertheless, they call themselves of the holy city, but they do not stay themselves upon the God of Israel, who is the Lord of Hosts; yea, the Lord of Hosts is his name."}], "48:3": [{"ref": "1 Ne 20:3", "source": "bom", "text": "Behold, I have declared the former things from the beginning; and they went forth out of my mouth, and I showed them. I did show them suddenly."}], "48:4": [{"ref": "1 Ne 20:4", "source": "bom", "text": "And I did it because I knew that thou art obstinate, and thy neck is an iron sinew, and thy brow brass;"}, {"ref": "Deut 31:27", "source": "ot", "text": "For I know thy rebellion, and thy stiff neck: behold, while I am yet alive with you this day, ye have been rebellious against the LORD; and how much more after my death?"}], "48:5": [{"ref": "1 Ne 20:5", "source": "bom", "text": "And I have even from the beginning declared to thee; before it came to pass I showed them thee; and I showed them for fear lest thou shouldst say—Mine idol hath done them, and my graven image, and my molten image hath commanded them."}], "48:6": [{"ref": "1 Ne 20:6", "source": "bom", "text": "Thou hast seen and heard all this; and will ye not declare them? And that I have showed thee new things from this time, even hidden things, and thou didst not know them."}], "48:7": [{"ref": "1 Ne 20:7", "source": "bom", "text": "They are created now, and not from the beginning, even before the day when thou heardest them not they were declared unto thee, lest thou shouldst say—Behold I knew them."}], "48:8": [{"ref": "1 Ne 20:8", "source": "bom", "text": "Yea, and thou heardest not; yea, thou knewest not; yea, from that time thine ear was not opened; for I knew that thou wouldst deal very treacherously, and wast called a transgressor from the womb."}], "48:9": [{"ref": "1 Ne 20:9", "source": "bom", "text": "Nevertheless, for my name's sake will I defer mine anger, and for my praise will I refrain from thee, that I cut thee not off."}, {"ref": "Ps 79:9", "source": "ot", "text": "Help us, O God of our salvation, for the glory of thy name: and deliver us, and purge away our sins, for thy name's sake."}], "48:10": [{"ref": "1 Ne 20:10", "source": "bom", "text": "For, behold, I have refined thee, I have chosen thee in the furnace of affliction."}, {"ref": "D&C 121:7-8", "source": "dc", "text": "My son, peace be unto thy soul; thine adversity and thine afflictions shall be but a small moment;"}, {"ref": "Mal 3:2-3", "source": "ot", "text": "But who may abide the day of his coming? and who shall stand when he appeareth? for he is like a refiner's fire, and like fullers' soap:"}], "48:11": [{"ref": "1 Ne 20:11", "source": "bom", "text": "For mine own sake, yea, for mine own sake will I do this, for I will not suffer my name to be polluted, and I will not give my glory unto another."}], "48:12": [{"ref": "1 Ne 20:12", "source": "bom", "text": "Hearken unto me, O Jacob, and Israel my called, for I am he; I am the first, and I am also the last."}, {"ref": "Rev 1:8", "source": "nt", "text": "I am Alpha and Omega, the beginning and the ending, saith the Lord, which is, and which was, and which is to come, the Almighty."}, {"ref": "Rev 22:13", "source": "nt", "text": "I am Alpha and Omega, the beginning and the end, the first and the last."}], "48:13": [{"ref": "1 Ne 20:13", "source": "bom", "text": "Mine hand hath also laid the foundation of the earth, and my right hand hath spanned the heavens. I call unto them and they stand up together."}], "48:14": [{"ref": "1 Ne 20:14", "source": "bom", "text": "All ye, assemble yourselves, and hear; who among them hath declared these things unto them? The Lord hath loved him; yea, and he will fulfil his word which he hath declared by them; and he will do his pleasure on Babylon, and his arm shall come upon the Chaldeans."}], "48:15": [{"ref": "1 Ne 20:15", "source": "bom", "text": "Also, saith the Lord; I the Lord, yea, I have spoken; yea, I have called him to declare, I have brought him, and he shall make his way prosperous."}], "48:16": [{"ref": "1 Ne 20:16", "source": "bom", "text": "Come ye near unto me; I have not spoken in secret; from the beginning, from the time that it was declared have I spoken; and the Lord God, and his Spirit, hath sent me."}, {"ref": "John 8:42", "source": "nt", "text": "Jesus said unto them, If God were your Father, ye would love me: for I proceeded forth and came from God; neither came I of myself, but he sent me."}], "48:17": [{"ref": "1 Ne 20:17", "source": "bom", "text": "And thus saith the Lord, thy Redeemer, the Holy One of Israel; I have sent him, the Lord thy God who teacheth thee to profit, who leadeth thee by the way thou shouldst go, hath done it."}], "48:18": [{"ref": "1 Ne 20:18", "source": "bom", "text": "O that thou hadst hearkened to my commandments—then had thy peace been as a river, and thy righteousness as the waves of the sea."}, {"ref": "Ps 119:165", "source": "ot", "text": "Great peace have they which love thy law: and nothing shall offend them."}], "48:19": [{"ref": "1 Ne 20:19", "source": "bom", "text": "Thy seed also had been as the sand; the offspring of thy bowels like the gravel thereof; his name should not have been cut off nor destroyed from before me."}], "48:20": [{"ref": "1 Ne 20:20", "source": "bom", "text": "Go ye forth of Babylon, flee ye from the Chaldeans, with a voice of singing declare ye, tell this, utter to the end of the earth; say ye: The Lord hath redeemed his servant Jacob."}, {"ref": "Rev 18:4", "source": "nt", "text": "And I heard another voice from heaven, saying, Come out of her, my people, that ye be not partakers of her sins, and that ye receive not of her plagues."}, {"ref": "D&C 133:5", "source": "dc", "text": "Go ye out from Babylon. Be ye clean that bear the vessels of the Lord."}, {"ref": "Jer 50:8", "source": "ot", "text": "Remove out of the midst of Babylon, and go forth out of the land of the Chaldeans, and be as the he goats before the flocks."}, {"ref": "Jer 51:6", "source": "ot", "text": "Flee out of the midst of Babylon, and deliver every man his soul: be not cut off in her iniquity; for this is the time of the LORD's vengeance; he will render unto her a recompence."}], "48:21": [{"ref": "1 Ne 20:21", "source": "bom", "text": "And they thirsted not; he led them through the deserts; he caused the waters to flow out of the rock for them; he clave the rock also and the waters gushed out."}, {"ref": "1 Cor 10:4", "source": "nt", "text": "And did all drink the same spiritual drink: for they drank of that spiritual Rock that followed them: and that Rock was Christ."}, {"ref": "Ex 17:6", "source": "ot", "text": "Behold, I will stand before thee there upon the rock in Horeb; and thou shalt smite the rock, and there shall come water out of it, that the people may drink. And Moses did so in the sight of the elders of Israel."}], "48:22": [{"ref": "1 Ne 20:22", "source": "bom", "text": "And notwithstanding he hath done all this, and greater also, there is no peace, saith the Lord, unto the wicked."}, {"ref": "Isa 57:21", "source": "ot", "text": "There is no peace, saith my God, to the wicked."}], "49:1": [{"ref": "1 Ne 21:1", "source": "bom", "text": "And again: Hearken, O ye house of Israel, all ye that are broken off and are driven out because of the wickedness of the pastors of my people; yea, all ye that are broken off, that are scattered abroad, who are of my people, O house of Israel. Listen, O isles, unto me, and hearken ye people from far; the Lord hath called me from the womb; from the bowels of my mother hath he made mention of my name."}, {"ref": "Jer 1:5", "source": "ot", "text": "Before I formed thee in the belly I knew thee; and before thou camest forth out of the womb I sanctified thee, and I ordained thee a prophet unto the nations."}, {"ref": "Gal 1:15", "source": "nt", "text": "But when it pleased God, who separated me from my mother's womb, and called me by his grace,"}, {"ref": "Abr 3:22-23", "source": "pgp", "text": "Now the Lord had shown unto me, Abraham, the intelligences that were organized before the world was; and among all these there were many of the noble and great ones;"}], "49:2": [{"ref": "1 Ne 21:2", "source": "bom", "text": "And he hath made my mouth like a sharp sword; in the shadow of his hand hath he hid me, and made me a polished shaft; in his quiver hath he hid me;"}, {"ref": "Heb 4:12", "source": "nt", "text": "For the word of God is quick, and powerful, and sharper than any twoedged sword, piercing even to the dividing asunder of soul and spirit, and of the joints and marrow, and is a discerner of the thoughts and intents of the heart."}, {"ref": "Rev 1:16", "source": "nt", "text": "And he had in his right hand seven stars: and out of his mouth went a sharp twoedged sword: and his countenance was as the sun shineth in his strength."}, {"ref": "Eph 6:17", "source": "nt", "text": "And take the helmet of salvation, and the sword of the Spirit, which is the word of God:"}], "49:3": [{"ref": "1 Ne 21:3", "source": "bom", "text": "And said unto me: Thou art my servant, O Israel, in whom I will be glorified."}], "49:4": [{"ref": "1 Ne 21:4", "source": "bom", "text": "Then I said, I have labored in vain, I have spent my strength for naught and in vain; surely my judgment is with the Lord, and my work with my God."}, {"ref": "D&C 121:1-6", "source": "dc", "text": "O God, where art thou? And where is the pavilion that covereth thy hiding place?"}], "49:5": [{"ref": "1 Ne 21:5", "source": "bom", "text": "And now, saith the Lord—that formed me from the womb that I should be his servant, to bring Jacob again to him—though Israel be not gathered, yet shall I be glorious in the eyes of the Lord, and my God shall be my strength."}], "49:6": [{"ref": "1 Ne 21:6", "source": "bom", "text": "And he said: It is a light thing that thou shouldst be my servant to raise up the tribes of Jacob, and to restore the preserved of Israel. I will also give thee for a light to the Gentiles, that thou mayest be my salvation unto the ends of the earth."}, {"ref": "Luke 2:32", "source": "nt", "text": "A light to lighten the Gentiles, and the glory of thy people Israel."}, {"ref": "Acts 13:47", "source": "nt", "text": "For so hath the Lord commanded us, saying, I have set thee to be a light of the Gentiles, that thou shouldest be for salvation unto the ends of the earth."}, {"ref": "Acts 26:23", "source": "nt", "text": "That Christ should suffer, and that he should be the first that should rise from the dead, and should shew light unto the people, and to the Gentiles."}], "49:7": [{"ref": "1 Ne 21:7", "source": "bom", "text": "Thus saith the Lord, the Redeemer of Israel, his Holy One, to him whom man despiseth, to him whom the nations abhorreth, to servant of rulers: Kings shall see and arise, princes also shall worship, because of the Lord that is faithful."}], "49:8": [{"ref": "1 Ne 21:8", "source": "bom", "text": "Thus saith the Lord: In an acceptable time have I heard thee, O isles of the sea, and in a day of salvation have I helped thee; and I will preserve thee, and give thee my servant for a covenant of the people, to establish the earth, to cause to inherit the desolate heritages;"}, {"ref": "2 Cor 6:2", "source": "nt", "text": "(For he saith, I have heard thee in a time accepted, and in the day of salvation have I succoured thee: behold, now is the accepted time; behold, now is the day of salvation.)"}], "49:9": [{"ref": "1 Ne 21:9", "source": "bom", "text": "That thou mayest say to the prisoners: Go forth; to them that sit in darkness: Show yourselves. They shall feed in the ways, and their pastures shall be in all high places."}], "49:10": [{"ref": "1 Ne 21:10", "source": "bom", "text": "They shall not hunger nor thirst, neither shall the heat nor the sun smite them; for he that hath mercy on them shall lead them, even by the springs of water shall he guide them."}, {"ref": "Rev 7:16-17", "source": "nt", "text": "They shall hunger no more, neither thirst any more; neither shall the sun light on them, nor any heat."}], "49:11": [{"ref": "1 Ne 21:11", "source": "bom", "text": "And I will make all my mountains a way, and my highways shall be exalted."}], "49:12": [{"ref": "1 Ne 21:12", "source": "bom", "text": "And then, O house of Israel, behold, these shall come from far; and lo, these from the north and from the west; and these from the land of Sinim."}], "49:13": [{"ref": "1 Ne 21:13", "source": "bom", "text": "Sing, O heavens; and be joyful, O earth; for the feet of those who are in the east shall be established; and break forth into singing, O mountains; for they shall be smitten no more; for the Lord hath comforted his people, and will have mercy upon his afflicted."}, {"ref": "Deut 32:43", "source": "ot", "text": "Rejoice, O ye nations, with his people: for he will avenge the blood of his servants, and will render vengeance to his adversaries, and will be merciful unto his land, and to his people."}], "49:14": [{"ref": "1 Ne 21:14", "source": "bom", "text": "But, behold, Zion hath said: The Lord hath forsaken me, and my Lord hath forgotten me—but he will show that he hath not."}], "49:15": [{"ref": "1 Ne 21:15", "source": "bom", "text": "For can a woman forget her sucking child, that she should not have compassion on the son of her womb? Yea, they may forget, yet will I not forget thee, O house of Israel."}, {"ref": "Ps 27:10", "source": "ot", "text": "When my father and my mother forsake me, then the LORD will take me up."}], "49:16": [{"ref": "1 Ne 21:16", "source": "bom", "text": "Behold, I have graven thee upon the palms of my hands; thy walls are continually before me."}, {"ref": "3 Ne 11:14-15", "source": "bom", "text": "Arise and come forth unto me, that ye may thrust your hands into my side, and also that ye may feel the prints of the nails in my hands and in my feet, that ye may know that I am the God of Israel, and the God of the whole earth, and have been slain for the sins of the world."}], "49:17": [{"ref": "1 Ne 21:17", "source": "bom", "text": "Thy children shall make haste against thy destroyers; and they that made thee waste shall go forth of thee."}], "49:18": [{"ref": "1 Ne 21:18", "source": "bom", "text": "Lift up thine eyes round about and behold; all these gather themselves together, and they shall come to thee. And as I live, saith the Lord, thou shalt surely clothe thee with them all, as with an ornament, and bind them on even as a bride."}], "49:19": [{"ref": "1 Ne 21:19", "source": "bom", "text": "For thy waste and thy desolate places, and the land of thy destruction, shall even now be too narrow by reason of the inhabitants; and they that swallowed thee up shall be far away."}], "49:20": [{"ref": "1 Ne 21:20", "source": "bom", "text": "The children whom thou shalt have, after thou hast lost the first, shall again in thine ears say: The place is too strait for me; give place to me that I may dwell."}], "49:21": [{"ref": "1 Ne 21:21", "source": "bom", "text": "Then shalt thou say in thine heart: Who hath begotten me these, seeing I have lost my children, and am desolate, a captive, and removing to and fro? And who hath brought up these? Behold, I was left alone; these, where have they been?"}], "49:22": [{"ref": "1 Ne 21:22", "source": "bom", "text": "Thus saith the Lord God: Behold, I will lift up mine hand to the Gentiles, and set up my standard to the people; and they shall bring thy sons in their arms, and thy daughters shall be carried upon their shoulders."}, {"ref": "1 Ne 22:6-8", "source": "bom", "text": "Nevertheless, after they shall be nursed by the Gentiles, and the Lord has lifted up his hand upon the Gentiles and set them up for a standard, and their children have been carried in their arms, and their daughters have been carried upon their shoulders, behold these things of which are spoken are temporal; for thus are the covenants of the Lord with our fathers; and it meaneth us in the days to come, and also all our brethren who are of the house of Israel."}, {"ref": "2 Ne 10:8-9", "source": "bom", "text": "And it shall come to pass that they shall be gathered in from their long dispersion, from the isles of the sea, and from the four parts of the earth; and the nations of the Gentiles shall be great in the eyes of me, saith God, in carrying them forth to the lands of their inheritance."}], "49:23": [{"ref": "1 Ne 21:23", "source": "bom", "text": "And kings shall be thy nursing fathers, and their queens thy nursing mothers; they shall bow down to thee with their face towards the earth, and lick up the dust of thy feet; and thou shalt know that I am the Lord; for they shall not be ashamed that wait for me."}, {"ref": "2 Ne 10:9", "source": "bom", "text": "Yea, the kings of the Gentiles shall be nursing fathers unto them, and their queens shall become nursing mothers; wherefore, the promises of the Lord are great unto the Gentiles, for he hath spoken it, and who can dispute?"}], "49:24": [{"ref": "1 Ne 21:24", "source": "bom", "text": "For shall the prey be taken from the mighty, or the lawful captives delivered?"}], "49:25": [{"ref": "1 Ne 21:25", "source": "bom", "text": "But thus saith the Lord, even the captives of the mighty shall be taken away, and the prey of the terrible shall be delivered; for I will contend with him that contendeth with thee, and I will save thy children."}], "49:26": [{"ref": "1 Ne 21:26", "source": "bom", "text": "And I will feed them that oppress thee with their own flesh; they shall be drunken with their own blood as with sweet wine; and all flesh shall know that I, the Lord, am thy Savior and thy Redeemer, the Mighty One of Jacob."}], "50:1": [{"ref": "2 Ne 7:1", "source": "bom", "text": "Yea, for thus saith the Lord: Have I put thee away, or have I cast thee off forever? For thus saith the Lord: Where is the bill of your mother's divorcement? To whom have I put thee away, or to which of my creditors have I sold you? Yea, to whom have I sold you? Behold, for your iniquities have ye sold yourselves, and for your transgressions is your mother put away."}], "50:2": [{"ref": "2 Ne 7:2", "source": "bom", "text": "Wherefore, when I came, there was no man; when I called, yea, there was none to answer. O house of Israel, is my hand shortened at all that it cannot redeem, or have I no power to deliver? Behold, at my rebuke I dry up the sea, I make their rivers a wilderness and their fish to stink because the waters are dried up, and they die because of thirst."}], "50:4": [{"ref": "2 Ne 7:4", "source": "bom", "text": "The Lord God hath given me the tongue of the learned, that I should know how to speak a word in season unto thee, O house of Israel. When ye are weary he waketh morning by morning. He waketh mine ear to hear as the learned."}], "50:5": [{"ref": "2 Ne 7:5", "source": "bom", "text": "The Lord God hath opened mine ear, and I was not rebellious, neither turned away back."}], "50:6": [{"ref": "2 Ne 7:6", "source": "bom", "text": "I gave my back to the smiter, and my cheeks to them that plucked off the hair. I hid not my face from shame and spitting."}, {"ref": "Matt 26:67", "source": "nt", "text": "Then did they spit in his face, and buffeted him; and others smote him with the palms of their hands,"}, {"ref": "Matt 27:26", "source": "nt", "text": "Then released he Barabbas unto them: and when he had scourged Jesus, he delivered him to be crucified."}], "50:7": [{"ref": "2 Ne 7:7", "source": "bom", "text": "For the Lord God will help me, therefore shall I not be confounded. Therefore have I set my face like a flint, and I know that I shall not be ashamed."}], "50:8": [{"ref": "2 Ne 7:8", "source": "bom", "text": "And the Lord is near, and he justifieth me. Who will contend with me? Let us stand together. Who is mine adversary? Let him come near me, and I will smite him with the strength of my mouth."}], "50:9": [{"ref": "2 Ne 7:9", "source": "bom", "text": "For the Lord God will help me. And all they who shall condemn me, behold, all they shall wax old as a garment, and the moth shall eat them up."}], "50:10": [{"ref": "2 Ne 7:10", "source": "bom", "text": "Who is among you that feareth the Lord, that obeyeth the voice of his servant, that walketh in darkness and hath no light?"}], "50:11": [{"ref": "2 Ne 7:11", "source": "bom", "text": "Behold all ye that kindle fire, that compass yourselves about with sparks, walk in the light of your fire and in the sparks which ye have kindled. This shall ye have of mine hand—ye shall lie down in sorrow."}], "51:1": [{"ref": "2 Ne 8:1", "source": "bom", "text": "Hearken unto me, ye that follow after righteousness. Look unto the rock from whence ye are hewn, and to the hole of the pit from whence ye are digged."}], "51:2": [{"ref": "2 Ne 8:2", "source": "bom", "text": "Look unto Abraham, your father, and unto Sarah, she that bare you; for I called him alone, and blessed him."}, {"ref": "Gen 12:1-3", "source": "ot", "text": "Now the LORD had said unto Abram, Get thee out of thy country, and from thy kindred, and from thy father's house, unto a land that I will shew thee:"}], "51:3": [{"ref": "2 Ne 8:3", "source": "bom", "text": "For the Lord shall comfort Zion, he will comfort all her waste places; and he will make her wilderness like Eden, and her desert like the garden of the Lord. Joy and gladness shall be found therein, thanksgiving and the voice of melody."}], "51:4": [{"ref": "2 Ne 8:4", "source": "bom", "text": "Hearken unto me, my people; and give ear unto me, O my nation; for a law shall proceed from me, and I will make my judgment to rest for a light for the people."}], "51:5": [{"ref": "2 Ne 8:5", "source": "bom", "text": "My righteousness is near; my salvation is gone forth, and mine arm shall judge the people. The isles shall wait upon me, and on mine arm shall they trust."}], "51:6": [{"ref": "2 Ne 8:6", "source": "bom", "text": "Lift up your eyes to the heavens, and look upon the earth beneath; for the heavens shall vanish away like smoke, and the earth shall wax old like a garment; and they that dwell therein shall die in like manner. But my salvation shall be forever, and my righteousness shall not be abolished."}], "51:7": [{"ref": "2 Ne 8:7", "source": "bom", "text": "Hearken unto me, ye that know righteousness, the people in whose heart I have written my law, fear ye not the reproach of men, neither be ye afraid of their revilings."}], "51:8": [{"ref": "2 Ne 8:8", "source": "bom", "text": "For the moth shall eat them up like a garment, and the worm shall eat them like wool. But my righteousness shall be forever, and my salvation from generation to generation."}], "51:9": [{"ref": "2 Ne 8:9", "source": "bom", "text": "Awake, awake! Put on strength, O arm of the Lord; awake as in the ancient days. Art thou not he that hath cut Rahab, and wounded the dragon?"}], "51:10": [{"ref": "2 Ne 8:10", "source": "bom", "text": "Art thou not he who hath dried the sea, the waters of the great deep; that hath made the depths of the sea a way for the ransomed to pass over?"}, {"ref": "Ex 14:21-22", "source": "ot", "text": "And Moses stretched out his hand over the sea; and the LORD caused the sea to go back by a strong east wind all that night, and made the sea dry land, and the waters were divided."}], "51:11": [{"ref": "2 Ne 8:11", "source": "bom", "text": "Therefore, the redeemed of the Lord shall return, and come with singing unto Zion; and everlasting joy and holiness shall be upon their heads; and they shall obtain gladness and joy; sorrow and mourning shall flee away."}], "51:12": [{"ref": "2 Ne 8:12", "source": "bom", "text": "I am he; yea, I am he that comforteth you. Behold, who art thou, that thou shouldst be afraid of man, who shall die, and of the son of man, who shall be made like unto grass?"}], "51:13": [{"ref": "2 Ne 8:13", "source": "bom", "text": "And forgettest the Lord thy maker, that hath stretched forth the heavens, and laid the foundations of the earth, and hast feared continually every day, because of the fury of the oppressor, as if he were ready to destroy? And where is the fury of the oppressor?"}], "51:15": [{"ref": "2 Ne 8:15", "source": "bom", "text": "But I am the Lord thy God, whose waves roared; the Lord of Hosts is my name."}], "51:16": [{"ref": "2 Ne 8:16", "source": "bom", "text": "And I have put my words in thy mouth, and have covered thee in the shadow of mine hand, that I may plant the heavens and lay the foundations of the earth, and say unto Zion: Behold, thou art my people."}], "51:17": [{"ref": "2 Ne 8:17", "source": "bom", "text": "Awake, awake, stand up, O Jerusalem, which hast drunk at the hand of the Lord the cup of his fury—thou hast drunken the dregs of the cup of trembling wrung out—"}], "51:18": [{"ref": "2 Ne 8:18", "source": "bom", "text": "And none to guide her among all the sons she hath brought forth; neither that taketh her by the hand, of all the sons she hath brought up."}], "51:19": [{"ref": "2 Ne 8:19", "source": "bom", "text": "These two sons are come unto thee, who shall be sorry for thee—thy desolation and destruction, and the famine and the sword—and by whom shall I comfort thee?"}], "51:20": [{"ref": "2 Ne 8:20", "source": "bom", "text": "Thy sons have fainted, save these two; they lie at the head of all the streets; as a wild bull in a net, they are full of the fury of the Lord, the rebuke of thy God."}], "51:21": [{"ref": "2 Ne 8:21", "source": "bom", "text": "Therefore hear now this, thou afflicted, and drunken, and not with wine:"}], "51:22": [{"ref": "2 Ne 8:22", "source": "bom", "text": "Thus saith thy Lord, the Lord and thy God pleadeth the cause of his people; behold, I have taken out of thine hand the cup of trembling, the dregs of the cup of my fury; thou shalt no more drink it again."}], "51:23": [{"ref": "2 Ne 8:23", "source": "bom", "text": "But I will put it into the hand of them that afflict thee; who have said to thy soul: Bow down, that we may go over—and thou hast laid thy body as the ground and as the street to them that went over."}], "51:25": [{"ref": "2 Ne 8:25", "source": "bom", "text": "Shake thyself from the dust; arise, sit down, O Jerusalem; loose thyself from the bands of thy neck, O captive daughter of Zion."}], "52:1": [{"ref": "D&C 113:7-8", "source": "dc", "text": "Questions by Elias Higbee: What is meant by the command in Isaiah, 52d chapter, 1st verse, which saith: Put on thy strength, O Zion—and what people had Isaiah reference to?"}, {"ref": "3 Ne 20:36", "source": "bom", "text": "And then shall be brought to pass that which is written: Awake, awake again, and put on thy strength, O Zion; put on thy beautiful garments, O Jerusalem, the holy city, for henceforth there shall no more come into thee the uncircumcised and the unclean."}, {"ref": "Moro 10:31", "source": "bom", "text": "And awake, and arise from the dust, O Jerusalem; yea, and put on thy beautiful garments, O daughter of Zion; and strengthen thy stakes and enlarge thy borders forever, that thou mayest no more be confounded, that the covenants of the Eternal Father which he hath made unto thee, O house of Israel, may be fulfilled."}], "52:2": [{"ref": "3 Ne 20:37", "source": "bom", "text": "Shake thyself from the dust; arise, sit down, O Jerusalem; loose thyself from the bands of thy neck, O captive daughter of Zion."}], "52:3": [{"ref": "3 Ne 20:38", "source": "bom", "text": "For thus saith the Lord: Ye have sold yourselves for naught, and ye shall be redeemed without money."}, {"ref": "1 Pet 1:18-19", "source": "nt", "text": "Forasmuch as ye know that ye were not redeemed with corruptible things, as silver and gold, from your vain conversation received by tradition from your fathers;"}], "52:7": [{"ref": "3 Ne 20:40", "source": "bom", "text": "And then shall they say: How beautiful upon the mountains are the feet of him that bringeth good tidings unto them, that publisheth peace; that bringeth good tidings unto them of good, that publisheth salvation; that saith unto Zion: Thy God reigneth!"}, {"ref": "Mosiah 15:14-18", "source": "bom", "text": "And these are they who have published peace, who have brought good tidings of good, who have published salvation; and said unto Zion: Thy God reigneth!"}, {"ref": "Rom 10:15", "source": "nt", "text": "And how shall they preach, except they be sent? as it is written, How beautiful are the feet of them that preach the gospel of peace, and bring glad tidings of good things!"}, {"ref": "Nahum 1:15", "source": "ot", "text": "Behold upon the mountains the feet of him that bringeth good tidings, that publisheth peace! O Judah, keep thy solemn feasts, perform thy vows: for the wicked shall no more pass through thee; he is utterly cut off."}], "52:8": [{"ref": "3 Ne 20:32-33", "source": "bom", "text": "Then shall their watchmen lift up their voice, and with the voice together shall they sing; for they shall see eye to eye."}, {"ref": "Mosiah 12:22", "source": "bom", "text": "Thy watchmen shall lift up the voice; with the voice together shall they sing; for they shall see eye to eye when the Lord shall bring again Zion;"}], "52:9": [{"ref": "3 Ne 20:34", "source": "bom", "text": "Then shall they break forth into joy—Sing together, ye waste places of Jerusalem; for the Father hath comforted his people, he hath redeemed Jerusalem."}], "52:10": [{"ref": "3 Ne 20:35", "source": "bom", "text": "The Father hath made bare his holy arm in the eyes of all the nations; and all the ends of the earth shall see the salvation of the Father; and the Father and I are one."}, {"ref": "Ps 98:3", "source": "ot", "text": "He hath remembered his mercy and his truth toward the house of Israel: all the ends of the earth have seen the salvation of our God."}], "52:11": [{"ref": "3 Ne 20:41", "source": "bom", "text": "And then shall a cry go forth: Depart ye, depart ye, go ye out from thence, touch not that which is unclean; go ye out of the midst of her; be ye clean that bear the vessels of the Lord."}, {"ref": "D&C 133:5", "source": "dc", "text": "Go ye out from Babylon. Be ye clean that bear the vessels of the Lord."}], "52:12": [{"ref": "3 Ne 20:42", "source": "bom", "text": "For ye shall not go out with haste nor go by flight; for the Lord will go before you, and the God of Israel shall be your rearward."}, {"ref": "D&C 133:15", "source": "dc", "text": "But verily, thus saith the Lord, let not your flight be in haste, but let all things be prepared before you; and he that goeth, let him not look back lest sudden destruction shall come upon him."}], "52:13": [{"ref": "Mosiah 14:1", "source": "bom", "text": "Yea, even doth not Isaiah say: Who hath believed our report, and to whom is the arm of the Lord revealed?"}, {"ref": "Acts 3:13", "source": "nt", "text": "The God of Abraham, and of Isaac, and of Jacob, the God of our fathers, hath glorified his Son Jesus; whom ye delivered up, and denied him in the presence of Pilate, when he was determined to let him go."}], "52:14": [{"ref": "Mosiah 14:2", "source": "bom", "text": "For he shall grow up before him as a tender plant, and as a root out of dry ground; he hath no form nor comeliness; and when we shall see him there is no beauty that we should desire him."}], "52:15": [{"ref": "3 Ne 21:8", "source": "bom", "text": "And when that day shall come, it shall come to pass that kings shall shut their mouths; for that which had not been told them shall they see; and that which they had not heard shall they consider."}, {"ref": "Rom 15:21", "source": "nt", "text": "But as it is written, To whom he was not spoken of, they shall see: and they that have not heard shall understand."}], "53:1": [{"ref": "Mosiah 14:1", "source": "bom", "text": "Yea, even doth not Isaiah say: Who hath believed our report, and to whom is the arm of the Lord revealed?"}, {"ref": "John 12:38", "source": "nt", "text": "That the saying of Esaias the prophet might be fulfilled, which he spake, Lord, who hath believed our report? and to whom hath the arm of the Lord been revealed?"}, {"ref": "Rom 10:16", "source": "nt", "text": "But they have not all obeyed the gospel. For Esaias saith, Lord, who hath believed our report?"}], "53:2": [{"ref": "Mosiah 14:2", "source": "bom", "text": "For he shall grow up before him as a tender plant, and as a root out of dry ground; he hath no form nor comeliness; and when we shall see him there is no beauty that we should desire him."}], "53:3": [{"ref": "Mosiah 14:3", "source": "bom", "text": "He is despised and rejected of men; a man of sorrows, and acquainted with grief; and we hid as it were our faces from him; he was despised, and we esteemed him not."}, {"ref": "Mark 9:12", "source": "nt", "text": "And he answered and told them, Elias verily cometh first, and restoreth all things; and how it is written of the Son of man, that he must suffer many things, and be set at nought."}], "53:4": [{"ref": "Mosiah 14:4", "source": "bom", "text": "Surely he has borne our griefs, and carried our sorrows; yet we did esteem him stricken, smitten of God, and afflicted."}, {"ref": "Matt 8:17", "source": "nt", "text": "That it might be fulfilled which was spoken by Esaias the prophet, saying, Himself took our infirmities, and bare our sicknesses."}, {"ref": "1 Pet 2:24", "source": "nt", "text": "Who his own self bare our sins in his own body on the tree, that we, being dead to sins, should live unto righteousness: by whose stripes ye were healed."}], "53:5": [{"ref": "Mosiah 14:5", "source": "bom", "text": "But he was wounded for our transgressions, he was bruised for our iniquities; the chastisement of our peace was upon him; and with his stripes we are healed."}, {"ref": "1 Pet 2:24", "source": "nt", "text": "Who his own self bare our sins in his own body on the tree, that we, being dead to sins, should live unto righteousness: by whose stripes ye were healed."}, {"ref": "D&C 19:16-19", "source": "dc", "text": "For behold, I, God, have suffered these things for all, that they might not suffer if they would repent;"}], "53:6": [{"ref": "Mosiah 14:6", "source": "bom", "text": "All we, like sheep, have gone astray; we have turned every one to his own way; and the Lord hath laid on him the iniquities of us all."}, {"ref": "1 Pet 2:25", "source": "nt", "text": "For ye were as sheep going astray; but are now returned unto the Shepherd and Bishop of your souls."}], "53:7": [{"ref": "Mosiah 14:7", "source": "bom", "text": "He was oppressed, and he was afflicted, yet he opened not his mouth; he is brought as a lamb to the slaughter, and as a sheep before her shearers is dumb so he opened not his mouth."}, {"ref": "Acts 8:32-35", "source": "nt", "text": "The place of the scripture which he read was this, He was led as a sheep to the slaughter; and like a lamb dumb before his shearer, so opened he not his mouth:"}, {"ref": "Matt 26:63", "source": "nt", "text": "But Jesus held his peace. And the high priest answered and said unto him, I adjure thee by the living God, that thou tell us whether thou be the Christ, the Son of God."}], "53:8": [{"ref": "Mosiah 14:8", "source": "bom", "text": "He was taken from prison and from judgment; and who shall declare his generation? For he was cut off out of the land of the living; for the transgressions of my people was he stricken."}], "53:9": [{"ref": "Mosiah 14:9", "source": "bom", "text": "And he made his grave with the wicked, and with the rich in his death; because he had done no evil, neither was any deceit in his mouth."}, {"ref": "1 Pet 2:22", "source": "nt", "text": "Who did no sin, neither was guile found in his mouth:"}], "53:10": [{"ref": "Mosiah 14:10", "source": "bom", "text": "Yet it pleased the Lord to bruise him; he hath put him to grief; when thou shalt make his soul an offering for sin he shall see his seed, he shall prolong his days, and the pleasure of the Lord shall prosper in his hand."}, {"ref": "2 Ne 2:7", "source": "bom", "text": "Behold, he offereth himself a sacrifice for sin, to answer the ends of the law, unto all those who have a broken heart and a contrite spirit; and unto none else can the ends of the law be answered."}], "53:11": [{"ref": "Mosiah 14:11", "source": "bom", "text": "He shall see the travail of his soul, and shall be satisfied; by his knowledge shall my righteous servant justify many; for he shall bear their iniquities."}], "53:12": [{"ref": "Mosiah 14:12", "source": "bom", "text": "Therefore will I divide him a portion with the great, and he shall divide the spoil with the strong; because he hath poured out his soul unto death; and he was numbered with the transgressors; and he bore the sins of many, and made intercession for the transgressors."}, {"ref": "Luke 22:37", "source": "nt", "text": "For I say unto you, that this that is written must yet be accomplished in me, And he was reckoned among the transgressors: for the things concerning me have an end."}, {"ref": "Mark 15:28", "source": "nt", "text": "And the scripture was fulfilled, which saith, And he was numbered with the transgressors."}], "54:1": [{"ref": "3 Ne 22:1", "source": "bom", "text": "And then shall that which is written come to pass: Sing, O barren, thou that didst not bear; break forth into singing, and cry aloud, thou that didst not travail with child; for more are the children of the desolate than the children of the married wife, saith the Lord."}, {"ref": "Gal 4:27", "source": "nt", "text": "For it is written, Rejoice, thou barren that bearest not; break forth and cry, thou that travailest not: for the desolate hath many more children than she which hath an husband."}], "54:2": [{"ref": "3 Ne 22:2", "source": "bom", "text": "Enlarge the place of thy tent, and let them stretch forth the curtains of thy habitations; spare not, lengthen thy cords and strengthen thy stakes;"}, {"ref": "D&C 82:14", "source": "dc", "text": "For Zion must increase in beauty, and in holiness; her borders must be enlarged; her stakes must be strengthened; yea, verily I say unto you, Zion must arise and put on her beautiful garments."}], "54:3": [{"ref": "3 Ne 22:3", "source": "bom", "text": "For thou shalt break forth on the right hand and on the left, and thy seed shall inherit the Gentiles and make the desolate cities to be inhabited."}], "54:4": [{"ref": "3 Ne 22:4", "source": "bom", "text": "Fear not, for thou shalt not be ashamed; neither be thou confounded, for thou shalt not be put to shame; for thou shalt forget the shame of thy youth, and shalt not remember the reproach of thy youth, and shalt not remember the reproach of thy widowhood any more."}], "54:5": [{"ref": "3 Ne 22:5", "source": "bom", "text": "For thy maker, thy husband, the Lord of Hosts is his name; and thy Redeemer, the Holy One of Israel—the God of the whole earth shall he be called."}], "54:6": [{"ref": "3 Ne 22:6", "source": "bom", "text": "For the Lord hath called thee as a woman forsaken and grieved in spirit, and a wife of youth, when thou wast refused, saith thy God."}], "54:7": [{"ref": "3 Ne 22:7", "source": "bom", "text": "For a small moment have I forsaken thee, but with great mercies will I gather thee."}], "54:8": [{"ref": "3 Ne 22:8", "source": "bom", "text": "In a little wrath I hid my face from thee for a moment, but with everlasting kindness will I have mercy on thee, saith the Lord thy Redeemer."}], "54:9": [{"ref": "3 Ne 22:9", "source": "bom", "text": "For this, the waters of Noah unto me, for as I have sworn that the waters of Noah should no more go over the earth, so have I sworn that I would not be wroth with thee."}, {"ref": "Gen 9:11", "source": "ot", "text": "And I will establish my covenant with you; neither shall all flesh be cut off any more by the waters of a flood; neither shall there any more be a flood to destroy the earth."}], "54:10": [{"ref": "3 Ne 22:10", "source": "bom", "text": "For the mountains shall depart and the hills be removed, but my kindness shall not depart from thee, neither shall the covenant of my peace be removed, saith the Lord that hath mercy on thee."}], "54:13": [{"ref": "3 Ne 22:13", "source": "bom", "text": "And all thy children shall be taught of the Lord; and great shall be the peace of thy children."}, {"ref": "John 6:45", "source": "nt", "text": "It is written in the prophets, And they shall be all taught of God. Every man therefore that hath heard, and hath learned of the Father, cometh unto me."}], "54:14": [{"ref": "3 Ne 22:14", "source": "bom", "text": "In righteousness shalt thou be established; thou shalt be far from oppression for thou shalt not fear, and from terror for it shall not come near thee."}], "54:17": [{"ref": "3 Ne 22:17", "source": "bom", "text": "No weapon that is formed against thee shall prosper; and every tongue that shall revile against thee in judgment thou shalt condemn. This is the heritage of the servants of the Lord, and their righteousness is of me, saith the Lord."}], "55:1": [{"ref": "2 Ne 9:50-51", "source": "bom", "text": "Come, my brethren, every one that thirsteth, come ye to the waters; and he that hath no money, come buy and eat; yea, come buy wine and milk without money and without price."}, {"ref": "Rev 22:17", "source": "nt", "text": "And the Spirit and the bride say, Come. And let him that heareth say, Come. And let him that is athirst come. And whosoever will, let him take the water of life freely."}, {"ref": "John 7:37", "source": "nt", "text": "In the last day, that great day of the feast, Jesus stood and cried, saying, If any man thirst, let him come unto me, and drink."}], "55:3": [{"ref": "Acts 13:34", "source": "nt", "text": "And as concerning that he raised him up from the dead, now no more to return to corruption, he said on this wise, I will give you the sure mercies of David."}], "55:6": [{"ref": "D&C 88:62-63", "source": "dc", "text": "And again, verily I say unto you, my friends, I leave these sayings with you to ponder in your hearts, with this commandment which I give unto you, that ye shall call upon me while I am near—"}], "55:8": [{"ref": "Ps 103:11", "source": "ot", "text": "For as the heaven is high above the earth, so great is his mercy toward them that fear him."}], "55:10": [{"ref": "Deut 32:2", "source": "ot", "text": "My doctrine shall drop as the rain, my speech shall distil as the dew, as the small rain upon the tender herb, and as the showers upon the grass:"}], "55:11": [{"ref": "D&C 1:37-38", "source": "dc", "text": "Search these commandments, for they are true and faithful, and the prophecies and promises which are in them shall all be fulfilled."}], "55:12": [{"ref": "1 Chr 16:33", "source": "ot", "text": "Then shall the trees of the wood sing out at the presence of the LORD, because he cometh to judge the earth."}], "58:3": [{"ref": "Matt 6:16", "source": "nt", "text": "Moreover when ye fast, be not, as the hypocrites, of a sad countenance: for they disfigure their faces, that they may appear unto men to fast. Verily I say unto you, They have their reward."}], "58:6": [{"ref": "Matt 25:35-36", "source": "nt", "text": "For I was an hungred, and ye gave me meat: I was thirsty, and ye gave me drink: I was a stranger, and ye took me in:"}], "58:7": [{"ref": "Matt 25:35-40", "source": "nt", "text": "For I was an hungred, and ye gave me meat: I was thirsty, and ye gave me drink: I was a stranger, and ye took me in:"}, {"ref": "Mosiah 4:26", "source": "bom", "text": "And now, for the sake of these things which I have spoken unto you—that is, for the sake of retaining a remission of your sins from day to day, that ye may walk guiltless before God—I would that ye should impart of your substance to the poor, every man according to that which he hath, such as feeding the hungry, clothing the naked, visiting the sick and administering to their relief, both spiritually and temporally, according to their wants."}], "58:8": [{"ref": "Ps 37:6", "source": "ot", "text": "And he shall bring forth thy righteousness as the light, and thy judgment as the noonday."}], "58:11": [{"ref": "Ps 37:3", "source": "ot", "text": "Trust in the LORD, and do good; so shalt thou dwell in the land, and verily thou shalt be fed."}], "58:13": [{"ref": "D&C 59:9-13", "source": "dc", "text": "And that thou mayest more fully keep thyself unspotted from the world, thou shalt go to the house of prayer and offer up thy sacraments upon my holy day;"}], "58:14": [{"ref": "Deut 32:13", "source": "ot", "text": "He made him ride on the high places of the earth, that he might eat the increase of the fields; and he made him to suck honey out of the rock, and oil out of the flinty rock;"}], "59:1": [{"ref": "Num 11:23", "source": "ot", "text": "And the LORD said unto Moses, Is the LORD's hand waxed short? thou shalt see now whether my word shall come to pass unto thee or not."}], "59:2": [{"ref": "Micah 3:4", "source": "ot", "text": "Then shall they cry unto the LORD, but he will not hear them: he will even hide his face from them at that time, as they have behaved themselves ill in their doings."}, {"ref": "D&C 101:7", "source": "dc", "text": "They were slow to hearken unto the voice of the Lord their God; therefore, the Lord their God is slow to hearken unto their prayers, to answer them in the day of their trouble."}], "59:16": [{"ref": "Ezek 22:30", "source": "ot", "text": "And I sought for a man among them, that should make up the hedge, and stand in the gap before me for the land, that I should not destroy it: but I found none."}], "59:17": [{"ref": "Eph 6:14-17", "source": "nt", "text": "Stand therefore, having your loins girt about with truth, and having on the breastplate of righteousness;"}, {"ref": "1 Thes 5:8", "source": "nt", "text": "But let us, who are of the day, be sober, putting on the breastplate of faith and love; and for an helmet, the hope of salvation."}], "59:20": [{"ref": "Rom 11:26", "source": "nt", "text": "And so all Israel shall be saved: as it is written, There shall come out of Sion the Deliverer, and shall turn away ungodliness from Jacob:"}], "59:21": [{"ref": "D&C 1:38", "source": "dc", "text": "What I the Lord have spoken, I have spoken, and I excuse not myself; and though the heavens and the earth pass away, my word shall not pass away, but shall all be fulfilled, whether by mine own voice or by the voice of my servants, it is the same."}], "60:1": [{"ref": "D&C 115:5", "source": "dc", "text": "Verily I say unto you all: Arise and shine forth, that thy light may be a standard for the nations;"}], "60:2": [{"ref": "Eph 6:12", "source": "nt", "text": "For we wrestle not against flesh and blood, but against principalities, against powers, against the rulers of the darkness of this world, against spiritual wickedness in high places."}], "60:3": [{"ref": "Rev 21:24", "source": "nt", "text": "And the nations of them which are saved shall walk in the light of it: and the kings of the earth do bring their glory and honour into it."}], "60:10": [{"ref": "Zech 6:15", "source": "ot", "text": "And they that are far off shall come and build in the temple of the LORD, and ye shall know that the LORD of hosts hath sent me unto you. And this shall come to pass, if ye will diligently obey the voice of the LORD your God."}], "60:11": [{"ref": "Rev 21:25-26", "source": "nt", "text": "And the gates of it shall not be shut at all by day: for there shall be no night there."}], "60:14": [{"ref": "Rev 3:9", "source": "nt", "text": "Behold, I will make them of the synagogue of Satan, which say they are Jews, and are not, but do lie; behold, I will make them to come and worship before thy feet, and to know that I have loved thee."}], "60:19": [{"ref": "Rev 21:23", "source": "nt", "text": "And the city had no need of the sun, neither of the moon, to shine in it: for the glory of God did lighten it, and the Lamb is the light thereof."}, {"ref": "Rev 22:5", "source": "nt", "text": "And there shall be no night there; and they need no candle, neither light of the sun; for the Lord God giveth them light: and they shall reign for ever and ever."}], "60:20": [{"ref": "Rev 21:4", "source": "nt", "text": "And God shall wipe away all tears from their eyes; and there shall be no more death, neither sorrow, nor crying, neither shall there be any more pain: for the former things are passed away."}], "60:21": [{"ref": "Matt 5:5", "source": "nt", "text": "Blessed are the meek: for they shall inherit the earth."}], "61:1": [{"ref": "Luke 4:18-21", "source": "nt", "text": "The Spirit of the Lord is upon me, because he hath anointed me to preach the gospel to the poor; he hath sent me to heal the brokenhearted, to preach deliverance to the captives, and recovering of sight to the blind, to set at liberty them that are bruised,"}, {"ref": "Matt 11:5", "source": "nt", "text": "The blind receive their sight, and the lame walk, the lepers are cleansed, and the deaf hear, the dead are raised up, and the poor have the gospel preached to them."}], "61:2": [{"ref": "Luke 4:19", "source": "nt", "text": "To preach the acceptable year of the Lord."}], "61:3": [{"ref": "D&C 101:13-16", "source": "dc", "text": "And they that have been scattered shall be gathered."}], "61:6": [{"ref": "1 Pet 2:5,9", "source": "nt"}, {"ref": "Rev 1:6", "source": "nt", "text": "And hath made us kings and priests unto God and his Father; to him be glory and dominion for ever and ever. Amen."}], "61:10": [{"ref": "Rev 19:7-8", "source": "nt", "text": "Let us be glad and rejoice, and give honour to him: for the marriage of the Lamb is come, and his wife hath made herself ready."}], "63:1": [{"ref": "Rev 19:13", "source": "nt", "text": "And he was clothed with a vesture dipped in blood: and his name is called The Word of God."}], "63:3": [{"ref": "Rev 14:20", "source": "nt", "text": "And the winepress was trodden without the city, and blood came out of the winepress, even unto the horse bridles, by the space of a thousand and six hundred furlongs."}, {"ref": "Rev 19:15", "source": "nt", "text": "And out of his mouth goeth a sharp sword, that with it he should smite the nations: and he shall rule them with a rod of iron: and he treadeth the winepress of the fierceness and wrath of Almighty God."}, {"ref": "D&C 133:48-51", "source": "dc", "text": "And the Lord shall be red in his apparel, and his garments like him that treadeth in the wine-vat."}], "63:4": [{"ref": "D&C 133:51", "source": "dc", "text": "And I have trampled them in my fury, and I did tread upon them in mine anger, and their blood have I sprinkled upon my garments, and stained all my raiment; for this was the day of vengeance which was in my heart."}], "63:7": [{"ref": "Ps 103:1-4", "source": "ot", "text": "Bless the LORD, O my soul: and all that is within me, bless his holy name."}], "63:9": [{"ref": "Ex 23:20-21", "source": "ot", "text": "Behold, I send an Angel before thee, to keep thee in the way, and to bring thee into the place which I have prepared."}, {"ref": "D&C 133:53", "source": "dc", "text": "In all their afflictions he was afflicted. And the angel of his presence saved them; and in his love, and in his pity, he redeemed them, and bore them, and carried them all the days of old;"}], "63:16": [{"ref": "Deut 32:6", "source": "ot", "text": "Do ye thus requite the LORD, O foolish people and unwise? is not he thy father that hath bought thee? hath he not made thee, and established thee?"}], "64:1": [{"ref": "D&C 133:40-44", "source": "dc", "text": "Calling upon the name of the Lord day and night, saying: O that thou wouldst rend the heavens, that thou wouldst come down, that the mountains might flow down at thy presence."}], "64:4": [{"ref": "1 Cor 2:9", "source": "nt", "text": "But as it is written, Eye hath not seen, nor ear heard, neither have entered into the heart of man, the things which God hath prepared for them that love him."}, {"ref": "D&C 76:10", "source": "dc", "text": "For by my Spirit will I enlighten them, and by my power will I make known unto them the secrets of my will—yea, even those things which eye has not seen, nor ear heard, nor yet entered into the heart of man."}], "64:8": [{"ref": "Jer 18:6", "source": "ot", "text": "O house of Israel, cannot I do with you as this potter? saith the LORD. Behold, as the clay is in the potter's hand, so are ye in mine hand, O house of Israel."}, {"ref": "Rom 9:21", "source": "nt", "text": "Hath not the potter power over the clay, of the same lump to make one vessel unto honour, and another unto dishonour?"}], "65:1": [{"ref": "Rom 10:20", "source": "nt", "text": "But Esaias is very bold, and saith, I was found of them that sought me not; I was made manifest unto them that asked not after me."}], "65:2": [{"ref": "Rom 10:21", "source": "nt", "text": "But to Israel he saith, All day long I have stretched forth my hands unto a disobedient and gainsaying people."}], "65:17": [{"ref": "2 Pet 3:13", "source": "nt", "text": "Nevertheless we, according to his promise, look for new heavens and a new earth, wherein dwelleth righteousness."}, {"ref": "Rev 21:1", "source": "nt", "text": "And I saw a new heaven and a new earth: for the first heaven and the first earth were passed away; and there was no more sea."}, {"ref": "D&C 29:23-24", "source": "dc", "text": "And the end shall come, and the heaven and the earth shall be consumed and pass away, and there shall be a new heaven and a new earth."}, {"ref": "Ether 13:9", "source": "bom", "text": "And there shall be a new heaven and a new earth; and they shall be like unto the old save the old have passed away, and all things have become new."}], "65:20": [{"ref": "D&C 101:29-31", "source": "dc", "text": "And there shall be no sorrow because there is no death."}, {"ref": "D&C 63:50-51", "source": "dc", "text": "And he that liveth when the Lord shall come, and hath kept the faith, blessed is he; nevertheless, it is appointed to him to die at the age of man."}], "65:25": [{"ref": "D&C 101:26", "source": "dc", "text": "And in that day the enmity of man, and the enmity of beasts, yea, the enmity of all flesh, shall cease from before my face."}], "66:1": [{"ref": "Matt 5:34-35", "source": "nt", "text": "But I say unto you, Swear not at all; neither by heaven; for it is God's throne:"}, {"ref": "Acts 7:49", "source": "nt", "text": "Heaven is my throne, and earth is my footstool: what house will ye build me? saith the Lord: or what is the place of my rest?"}], "66:2": [{"ref": "D&C 59:8", "source": "dc", "text": "Thou shalt offer a sacrifice unto the Lord thy God in righteousness, even that of a broken heart and a contrite spirit."}], "66:15": [{"ref": "2 Thes 1:7-8", "source": "nt", "text": "And to you who are troubled rest with us, when the Lord Jesus shall be revealed from heaven with his mighty angels,"}, {"ref": "D&C 29:9", "source": "dc", "text": "For the hour is nigh and the day soon at hand when the earth is ripe; and all the proud and they that do wickedly shall be as stubble; and I will burn them up, saith the Lord of Hosts, that wickedness shall not be upon the earth;"}], "66:18": [{"ref": "Matt 25:32", "source": "nt", "text": "And before him shall be gathered all nations: and he shall separate them one from another, as a shepherd divideth his sheep from the goats:"}], "66:20": [{"ref": "D&C 133:8-13", "source": "dc", "text": "Send forth the elders of my church unto the nations which are afar off; unto the islands of the sea; send forth unto foreign lands; call upon all nations, first upon the Gentiles, and then upon the Jews."}], "66:22": [{"ref": "2 Pet 3:13", "source": "nt", "text": "Nevertheless we, according to his promise, look for new heavens and a new earth, wherein dwelleth righteousness."}, {"ref": "Rev 21:1", "source": "nt", "text": "And I saw a new heaven and a new earth: for the first heaven and the first earth were passed away; and there was no more sea."}], "66:24": [{"ref": "Mark 9:48", "source": "nt", "text": "Where their worm dieth not, and the fire is not quenched."}]};
